const SLIPS_RAW = [{"id":1,"q1":"//CreateEmployee \npackage FileHandling;\n\nimport java.io.*;\nimport java.util.Scanner;\n\npublic class CreateEmployee{\n    public static void main(String[] args) {\n\n        try {\n\n            File file = new File(\"employee.txt\");\n\n            if(file.createNewFile()) {\n                System.out.println(\"File created: \" + file.getName());\n            }\n\n            Scanner sc = new Scanner(System.in);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n            sc.nextLine();\n\n            // Check duplicate ID\n            boolean exists = false;\n\n            Scanner reader = new Scanner(file);\n\n            while(reader.hasNextLine()) {\n\n                String line = reader.nextLine();\n\n                if(line.startsWith(\"Employee ID:\")) {\n\n                    int existingId =\n                            Integer.parseInt(line.substring(13).trim());\n\n                    if(existingId == id) {\n                        exists = true;\n                        break;\n                    }\n                }\n            }\n\n            reader.close();\n\n            if(exists) {\n                System.out.println(\"Employee ID already exists.\");\n            }\n            else {\n\n                FileWriter writer =\n                        new FileWriter(file, true);\n\n                System.out.print(\"Enter Employee Name: \");\n                String name = sc.nextLine();\n\n                System.out.print(\"Enter Employee Salary: \");\n                float salary = sc.nextFloat();\n                sc.nextLine();\n\n                System.out.print(\"Enter Department: \");\n                String dept = sc.nextLine();\n\n                writer.write(\"\\nEmployee ID: \" + id + \"\\n\");\n                writer.write(\"Employee Name: \" + name + \"\\n\");\n                writer.write(\"Employee Salary: \" + salary + \"\\n\");\n                writer.write(\"Department: \" + dept + \"\\n\");\n\n                writer.close();\n\n                System.out.println(\n                        \"Employee data written successfully.\");\n            }\n\n        } catch(IOException e) {\n            System.out.println(\"Error occurred.\");\n        }\n    }\n}\n\n\n// Read\n\n\npackage FileHandling;\n\nimport java.io.File;\nimport java.io.FileNotFoundException;\nimport java.util.Scanner;\n\npublic class ReadEmployee {\n    public static void main(String[] args) {\n\n        try {\n            File file = new File(\"employee.txt\");\n\n            Scanner reader = new Scanner(file);\n\n            System.out.println(\"\\nEmployee Records\\n\");\n\n            while(reader.hasNextLine()) {\n                String data = reader.nextLine();\n                System.out.println(data);\n            }\n\n            reader.close();\n\n        } catch(FileNotFoundException e) {\n            System.out.println(\"File not found.\");\n        }\n    }\n}\n\n\n//Delete\n\n\npackage FileHandling;\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass DeleteEmployee\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        try\n        {\n            File inputFile = new File(\"employee.txt\");\n            File tempFile = new File(\"temp.txt\");\n\n            BufferedReader br = new BufferedReader(\n                    new FileReader(inputFile));\n\n            BufferedWriter bw = new BufferedWriter(\n                    new FileWriter(tempFile));\n\n            System.out.println(\"Enter Employee ID to Delete:\");\n            int deleteId = sc.nextInt();\n\n            String line;\n\n            while((line = br.readLine()) != null)\n            {\n                if(line.startsWith(\"Employee ID:\"))\n                {\n                    int id = Integer.parseInt(\n                            line.substring(13).trim());\n\n                    String name = br.readLine();\n                    String salary = br.readLine();\n                    String dept = br.readLine();\n\n                    if(id != deleteId)\n                    {\n                        bw.write(line);\n                        bw.newLine();\n\n                        bw.write(name);\n                        bw.newLine();\n\n                        bw.write(salary);\n                        bw.newLine();\n\n                        bw.write(dept);\n                        bw.newLine();\n                    }\n                }\n            }\n\n            br.close();\n            bw.close();\n\n            inputFile.delete();\n            tempFile.renameTo(inputFile);\n\n            System.out.println(\"Record Deleted\");\n        }\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n} \n\n\n// Write/Update \n\n\npackage FileHandling;\n\nimport java.io.FileWriter;\nimport java.io.IOException;\nimport java.util.Scanner;\n\npublic class UpdateEmployee {\n    public static void main(String[] args) {\n\n        try {\n\n            FileWriter writer = new FileWriter(\"employee.txt\", true);\n\n            Scanner sc = new Scanner(System.in);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n            sc.nextLine();\n\n            System.out.print(\"Enter Employee Name: \");\n            String name = sc.nextLine();\n\n            System.out.print(\"Enter Employee Salary: \");\n            float salary = sc.nextFloat();\n            sc.nextLine();\n\n            System.out.print(\"Enter Department: \");\n            String dept = sc.nextLine();\n\n            writer.write(\"\\nEmployee ID: \" + id + \"\\n\");\n            writer.write(\"Employee Name: \" + name + \"\\n\");\n            writer.write(\"Employee Salary: \" + salary + \"\\n\");\n            writer.write(\"Department: \" + dept + \"\\n\");\n\n            writer.close();\n\n            System.out.println(\"New employee data added.\");\n\n        } catch(IOException e) {\n            System.out.println(\"Error writing to file.\");\n        }\n    }\n}","q2":"/*Develop a Java application that connects to a MySQL database to manage student\ninformation. Implement CRUD operations for student records using JDBC. Use\nprepared statements to handle SQL queries securely and ensure proper transaction\nmanagement.\n\ndatabase code :\n CREATE DATABASE studentdb;\n\n USE studentdb;\n\n CREATE TABLE student(\n    id INT PRIMARY KEY,\n    name VARCHAR(50),\n    marks INT);\n*/\n\n\nimport java.sql.*;\nimport java.util.Scanner;\n\nclass StudentCRUD\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        try\n        {\n            Class.forName(\"com.mysql.cj.jdbc.Driver\");\n\n            Connection con = DriverManager.getConnection(\n                    \"jdbc:mysql://localhost:3306/studentdb\",\n                    \"root\",\n                    \"@zekky@999\"\n            );\n\n            int choice;\n\n            do\n            {\n                System.out.println(\"\\n1. Insert\");\n                System.out.println(\"2. Display\");\n                System.out.println(\"3. Update\");\n                System.out.println(\"4. Delete\");\n                System.out.println(\"5. Exit\");\n\n                System.out.println(\"Enter Choice:\");\n                choice = sc.nextInt();\n\n                switch(choice)\n                {\n                    case 1:\n                        PreparedStatement ps =\n                                con.prepareStatement(\n                                        \"insert into student values(?,?,?)\");\n\n                        System.out.println(\"Enter ID:\");\n                        int id = sc.nextInt();\n                        sc.nextLine();\n\n                        System.out.println(\"Enter Name:\");\n                        String name = sc.nextLine();\n\n                        System.out.println(\"Enter Marks:\");\n                        int marks = sc.nextInt();\n\n                        ps.setInt(1, id);\n                        ps.setString(2, name);\n                        ps.setInt(3, marks);\n\n                        ps.executeUpdate();\n\n                        System.out.println(\"Record Inserted\");\n                        break;\n\n                    case 2:\n                        Statement st = con.createStatement();\n\n                        ResultSet rs =\n                                st.executeQuery(\"select * from student\");\n\n                        System.out.println(\"\\nStudent Records:\");\n\n                        while(rs.next())\n                        {\n                            System.out.println(\n                                    rs.getInt(1) + \" \"\n                                            + rs.getString(2) + \" \"\n                                            + rs.getInt(3));\n                        }\n                        break;\n\n                    case 3:\n                        PreparedStatement ps2 =\n                                con.prepareStatement(\n                                        \"update student set marks=? where id=?\");\n\n                        System.out.println(\"Enter New Marks:\");\n                        int m = sc.nextInt();\n\n                        System.out.println(\"Enter Student ID:\");\n                        int sid = sc.nextInt();\n\n                        ps2.setInt(1, m);\n                        ps2.setInt(2, sid);\n\n                        ps2.executeUpdate();\n\n                        System.out.println(\"Record Updated\");\n                        break;\n\n                    case 4:\n                        PreparedStatement ps3 =\n                                con.prepareStatement(\n                                        \"delete from student where id=?\");\n\n                        System.out.println(\"Enter Student ID:\");\n                        int did = sc.nextInt();\n\n                        ps3.setInt(1, did);\n\n                        ps3.executeUpdate();\n\n                        System.out.println(\"Record Deleted\");\n                        break;\n\n                    case 5:\n                        System.out.println(\"Exiting...\");\n                        break;\n\n                    default:\n                        System.out.println(\"Invalid Choice\");\n                }\n\n            } while(choice != 5);\n\n            con.close();\n        }\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}"},{"id":2,"q1":"/*Create a hierarchy of Employee, Manager, Sales Manager, they should have the\nfollowing functionality:\nA. Employee: Display name, date of birth and id of Employee.\nB. Manager: Display all above information with salary drawn.\nC. Sales Manager: Display all above information and commission if applicable. */\n\n\n   import java.util.Scanner;\n\nclass Employee\n{\n    int id;\n    String name, dob;\n\n    void getEmployee()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Employee ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Employee Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Date of Birth:\");\n        dob = sc.nextLine();\n    }\n\n    void displayEmployee()\n    {\n        System.out.println(\"\\n----- EMPLOYEE DETAILS -----\");\n\n        System.out.println(\"Employee ID: \" + id);\n        System.out.println(\"Employee Name: \" + name);\n        System.out.println(\"Date of Birth: \" + dob);\n    }\n}\n\nclass Manager extends Employee\n{\n    double salary;\n\n    void getManager()\n    {\n        getEmployee();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Salary:\");\n        salary = sc.nextDouble();\n    }\n\n    void displayManager()\n    {\n        displayEmployee();\n\n        System.out.println(\"\\n----- MANAGER DETAILS -----\");\n\n        System.out.println(\"Salary: \" + salary);\n    }\n}\n\nclass SalesManager extends Manager\n{\n    double commission;\n\n    void getSalesManager()\n    {\n        getManager();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Commission:\");\n        commission = sc.nextDouble();\n    }\n\n    void displaySalesManager()\n    {\n        displayManager();\n\n        System.out.println(\n        \"\\n----- SALES MANAGER DETAILS -----\");\n\n        System.out.println(\n        \"Commission: \" + commission);\n    }\n}\n\npublic class EmployeeHierarchy\n{\n    public static void main(String args[])\n    {\n        SalesManager s = new SalesManager();\n\n        s.getSalesManager();\n\n        s.displaySalesManager();\n    }\n}","q2":"/*Write a program to demonstrate how the process tasks asynchronously in a Spring\nBoot application.*/\n\n/* 1.go to start.spring.import \n2.download file \n3.open the file in intellij and run the application\n4.go to src/main/java/com/example/demo/DemoApplication.java\n5.create class AsyncService,AsyncController,AsyncDemoApplication */\n\n/* ADD code in AsyncDemoApplication.java */\npackage com.example.firstdemo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.scheduling.annotation.EnableAsync;\n\n@SpringBootApplication\n@EnableAsync\npublic class AsyncDemoApplication {\n    public static void main (String[] args) {\n        SpringApplication.run(AsyncDemoApplication.class, args);\n    }\n\n}\n\n\n/* Add code in AsyncService.java */\npackage com.example.firstdemo;\n\nimport org.springframework.scheduling.annotation.Async;\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class AsyncService {\n\n    @Async\n    public void processTask() {\n        try {\n            System.out.println(\"Task started on thread: \" +\n                    Thread.currentThread().getName());\n\n            Thread.sleep(5000); // simulate long process (5 seconds)\n\n            System.out.println(\"Task completed on thread:\" +\n                    Thread.currentThread().getName());\n\n        } catch (InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n/* Add code in AsyncController.java */\npackage com.example.firstdemo;\n\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.RestController;\n\n@RestController\npublic class AsyncController {\n\n    @Autowired\n    private AsyncService asyncService;\n\n    @GetMapping(\"/run\")\n    public String runTask() {\n        asyncService.processTask();\n        return \"Task triggered successfully\";\n    }\n}"},{"id":3,"q1":"/*Create a Java program to manage employee payroll using OOP concepts. Include\nfunctionalities such as employee creation, salary calculation, bonus allocation, and\npayslip generation. Use inheritance for different employee types (e.g., full-time,\npart-time).*/\n\n\nimport java.util.Scanner;\n\n// Base Class\nclass Employee {\n    int id;\n    String name;\n    double salary;\n    double bonus;\n\n    // Method to accept employee details\n    void getEmployeeData(int i, String n) {\n        id = i;\n        name = n;\n    }\n\n    // Method to calculate salary\n    void calculateSalary() {\n        // Overridden in child classes\n    }\n\n    // Method to allocate bonus\n    void allocateBonus(double b) {\n        bonus = b;\n    }\n\n    // Method to generate payslip\n    void generatePayslip() {\n        System.out.println(\"\\n===== PAYSLIP =====\");\n        System.out.println(\"Employee ID : \" + id);\n        System.out.println(\"Employee Name : \" + name);\n        System.out.println(\"Salary : \" + salary);\n        System.out.println(\"Bonus : \" + bonus);\n        System.out.println(\"Total Salary : \" + (salary + bonus));\n    }\n}\n\n// Full-Time Employee\nclass FullTimeEmployee extends Employee {\n    double monthlySalary;\n\n    void getFullTimeData(int i, String n, double ms) {\n        getEmployeeData(i, n);\n        monthlySalary = ms;\n    }\n\n    // Salary calculation\n    void calculateSalary() {\n        salary = monthlySalary;\n    }\n}\n\n// Part-Time Employee\nclass PartTimeEmployee extends Employee {\n    int hoursWorked;\n    double ratePerHour;\n\n    void getPartTimeData(int i, String n, int h, double r) {\n        getEmployeeData(i, n);\n        hoursWorked = h;\n        ratePerHour = r;\n    }\n\n    // Salary calculation\n    void calculateSalary() {\n        salary = hoursWorked * ratePerHour;\n    }\n}\n\n// Main Class\npublic class PayrollSystem {\n    public static void main(String[] args) {\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"===== Employee Payroll System =====\");\n\n        // Choice\n        System.out.println(\"\\nSelect Employee Type:\");\n        System.out.println(\"1. Full-Time Employee\");\n        System.out.println(\"2. Part-Time Employee\");\n        System.out.print(\"Enter Choice: \");\n\n        int choice = sc.nextInt();\n\n        // Full-Time Employee\n        if (choice == 1) {\n\n            FullTimeEmployee ft = new FullTimeEmployee();\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n            sc.nextLine();\n\n            System.out.print(\"Enter Employee Name: \");\n            String name = sc.nextLine();\n\n            System.out.print(\"Enter Monthly Salary: \");\n            double salary = sc.nextDouble();\n\n            System.out.print(\"Enter Bonus: \");\n            double bonus = sc.nextDouble();\n\n            ft.getFullTimeData(id, name, salary);\n\n            ft.calculateSalary();\n\n            ft.allocateBonus(bonus);\n\n            ft.generatePayslip();\n        }\n\n        // Part-Time Employee\n        else if (choice == 2) {\n\n            PartTimeEmployee pt = new PartTimeEmployee();\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n            sc.nextLine();\n\n            System.out.print(\"Enter Employee Name: \");\n            String name = sc.nextLine();\n\n            System.out.print(\"Enter Hours Worked: \");\n            int hours = sc.nextInt();\n\n            System.out.print(\"Enter Rate Per Hour: \");\n            double rate = sc.nextDouble();\n\n            System.out.print(\"Enter Bonus: \");\n            double bonus = sc.nextDouble();\n\n            pt.getPartTimeData(id, name, hours, rate);\n\n            pt.calculateSalary();\n\n            pt.allocateBonus(bonus);\n\n            pt.generatePayslip();\n        }\n\n        else {\n            System.out.println(\"Invalid Choice!\");\n        }\n\n        sc.close();\n    }\n}","q2":"/*Write a program to design an admission enquiry for MCA student form using\nSwing.*/\n\n\nimport javax.swing.*;\nimport java.awt.*;\nimport java.awt.event.*;\n\nclass MCAAdmissionForm extends JFrame implements ActionListener\n{\n    JLabel l1, l2, l3, l4, l5, l6;\n    JTextField t1, t2, t3;\n    JRadioButton r1, r2;\n    JComboBox c1;\n    JButton b1;\n\n    MCAAdmissionForm()\n    {\n        setTitle(\"MCA Admission Enquiry Form\");\n\n        l1 = new JLabel(\"Student Name:\");\n        l2 = new JLabel(\"Mobile Number:\");\n        l3 = new JLabel(\"Email ID:\");\n        l4 = new JLabel(\"Gender:\");\n        l5 = new JLabel(\"City:\");\n        l6 = new JLabel(\"Course:\");\n\n        t1 = new JTextField();\n        t2 = new JTextField();\n        t3 = new JTextField();\n\n        r1 = new JRadioButton(\"Male\");\n        r2 = new JRadioButton(\"Female\");\n\n        ButtonGroup bg = new ButtonGroup();\n        bg.add(r1);\n        bg.add(r2);\n\n        String course[] = {\"MCA\", \"MBA\", \"MSc IT\"};\n        c1 = new JComboBox(course);\n\n        b1 = new JButton(\"Submit\");\n\n        setLayout(null);\n\n        l1.setBounds(50, 50, 120, 30);\n        t1.setBounds(180, 50, 150, 30);\n\n        l2.setBounds(50, 100, 120, 30);\n        t2.setBounds(180, 100, 150, 30);\n\n        l3.setBounds(50, 150, 120, 30);\n        t3.setBounds(180, 150, 150, 30);\n\n        l4.setBounds(50, 200, 120, 30);\n        r1.setBounds(180, 200, 80, 30);\n        r2.setBounds(260, 200, 80, 30);\n\n        l5.setBounds(50, 250, 120, 30);\n\n        String city[] = {\"Mumbai\", \"Pune\", \"Nashik\"};\n        JComboBox cityBox = new JComboBox(city);\n        cityBox.setBounds(180, 250, 150, 30);\n\n        l6.setBounds(50, 300, 120, 30);\n        c1.setBounds(180, 300, 150, 30);\n\n        b1.setBounds(150, 370, 100, 30);\n\n        add(l1);\n        add(t1);\n\n        add(l2);\n        add(t2);\n\n        add(l3);\n        add(t3);\n\n        add(l4);\n        add(r1);\n        add(r2);\n\n        add(l5);\n        add(cityBox);\n\n        add(l6);\n        add(c1);\n\n        add(b1);\n\n        b1.addActionListener(this);\n\n        setSize(450, 500);\n        setVisible(true);\n        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        JOptionPane.showMessageDialog(this,\n                \"Admission Enquiry Submitted Successfully\");\n    }\n\n    public static void main(String args[])\n    {\n        new MCAAdmissionForm();\n    }\n}"},{"id":4,"q1":"/*Develop a Java application to manage student records using object-oriented\nprinciples. The system should support student registration, updating details,\ncalculating grades, and displaying student information.*/\n\n\n\nimport java.util.Scanner;\n\nclass Student\n{\n    int rollNo, sub1, sub2, sub3, total;\n    double percentage;\n    String name;\n    char grade;\n\n    void registerStudent()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Roll Number:\");\n        rollNo = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Student Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Subject 1 Marks:\");\n        sub1 = sc.nextInt();\n\n        System.out.println(\"Enter Subject 2 Marks:\");\n        sub2 = sc.nextInt();\n\n        System.out.println(\"Enter Subject 3 Marks:\");\n        sub3 = sc.nextInt();\n\n        calculateResult();\n\n        System.out.println(\"Student Registered Successfully.\");\n    }\n\n    void calculateResult()\n    {\n        total = sub1 + sub2 + sub3;\n\n        percentage = total / 3.0;\n\n        if(percentage >= 75)\n            grade = 'A';\n\n        else if(percentage >= 60)\n            grade = 'B';\n\n        else if(percentage >= 40)\n            grade = 'C';\n\n        else\n            grade = 'F';\n    }\n\n    void updateDetails()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        int choice;\n\n        System.out.println(\"\\n1. Update Name\");\n        System.out.println(\"2. Update Marks\");\n\n        System.out.println(\"Enter Choice:\");\n        choice = sc.nextInt();\n        sc.nextLine();\n\n        switch(choice)\n        {\n            case 1:\n\n                System.out.println(\"Enter New Name:\");\n                name = sc.nextLine();\n\n                System.out.println(\"Name Updated Successfully.\");\n                break;\n\n            case 2:\n\n                System.out.println(\"Enter New Subject 1 Marks:\");\n                sub1 = sc.nextInt();\n\n                System.out.println(\"Enter New Subject 2 Marks:\");\n                sub2 = sc.nextInt();\n\n                System.out.println(\"Enter New Subject 3 Marks:\");\n                sub3 = sc.nextInt();\n\n                calculateResult();\n\n                System.out.println(\"Marks Updated Successfully.\");\n                break;\n\n            default:\n                System.out.println(\"Invalid Choice\");\n        }\n    }\n\n    void display()\n    {\n        System.out.println(\"\\n----- Student Information -----\");\n\n        System.out.println(\"Roll No: \" + rollNo);\n        System.out.println(\"Name: \" + name);\n\n        System.out.println(\"Subject 1: \" + sub1);\n        System.out.println(\"Subject 2: \" + sub2);\n        System.out.println(\"Subject 3: \" + sub3);\n\n        System.out.println(\"Total: \" + total);\n        System.out.println(\"Percentage: \" + percentage);\n        System.out.println(\"Grade: \" + grade);\n    }\n}\n\npublic class StudentManagementSystem\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Student s = new Student();\n\n        int choice;\n\n        do\n        {\n            System.out.println(\"\\n1. Register\");\n            System.out.println(\"2. Update\");\n            System.out.println(\"3. Display\");\n            System.out.println(\"4. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n                    s.registerStudent();\n                    break;\n\n                case 2:\n                    s.updateDetails();\n                    break;\n\n                case 3:\n                    s.display();\n                    break;\n\n                case 4:\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 4);\n    }\n}","q2":"/*Develop a Java application that connects to a MySQL database to manage student\ninformation. Implement CRUD operations for student records using JDBC. Use\nprepared statements to handle SQL queries securely and ensure proper transaction\nmanagement.\n\ndatabase code :\n CREATE DATABASE studentdb;\n\n USE studentdb;\n\n CREATE TABLE student(\n    id INT PRIMARY KEY,\n    name VARCHAR(50),\n    marks INT);\n*/\n\nimport java.sql.*;\nimport java.util.Scanner;\n\nclass StudentCRUD\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        try\n        {\n            Class.forName(\"com.mysql.cj.jdbc.Driver\");\n\n            Connection con = DriverManager.getConnection(\n                    \"jdbc:mysql://localhost:3306/studentdb\",\n                    \"root\",\n                    \"@zekky@999\"\n            );\n\n            int choice;\n\n            do\n            {\n                System.out.println(\"\\n1. Insert\");\n                System.out.println(\"2. Display\");\n                System.out.println(\"3. Update\");\n                System.out.println(\"4. Delete\");\n                System.out.println(\"5. Exit\");\n\n                System.out.println(\"Enter Choice:\");\n                choice = sc.nextInt();\n\n                switch(choice)\n                {\n                    case 1:\n                        PreparedStatement ps =\n                                con.prepareStatement(\n                                        \"insert into student values(?,?,?)\");\n\n                        System.out.println(\"Enter ID:\");\n                        int id = sc.nextInt();\n                        sc.nextLine();\n\n                        System.out.println(\"Enter Name:\");\n                        String name = sc.nextLine();\n\n                        System.out.println(\"Enter Marks:\");\n                        int marks = sc.nextInt();\n\n                        ps.setInt(1, id);\n                        ps.setString(2, name);\n                        ps.setInt(3, marks);\n\n                        ps.executeUpdate();\n\n                        System.out.println(\"Record Inserted\");\n                        break;\n\n                    case 2:\n                        Statement st = con.createStatement();\n\n                        ResultSet rs =\n                                st.executeQuery(\"select * from student\");\n\n                        System.out.println(\"\\nStudent Records:\");\n\n                        while(rs.next())\n                        {\n                            System.out.println(\n                                    rs.getInt(1) + \" \"\n                                            + rs.getString(2) + \" \"\n                                            + rs.getInt(3));\n                        }\n                        break;\n\n                    case 3:\n                        PreparedStatement ps2 =\n                                con.prepareStatement(\n                                        \"update student set marks=? where id=?\");\n\n                        System.out.println(\"Enter New Marks:\");\n                        int m = sc.nextInt();\n\n                        System.out.println(\"Enter Student ID:\");\n                        int sid = sc.nextInt();\n\n                        ps2.setInt(1, m);\n                        ps2.setInt(2, sid);\n\n                        ps2.executeUpdate();\n\n                        System.out.println(\"Record Updated\");\n                        break;\n\n                    case 4:\n                        PreparedStatement ps3 =\n                                con.prepareStatement(\n                                        \"delete from student where id=?\");\n\n                        System.out.println(\"Enter Student ID:\");\n                        int did = sc.nextInt();\n\n                        ps3.setInt(1, did);\n\n                        ps3.executeUpdate();\n\n                        System.out.println(\"Record Deleted\");\n                        break;\n\n                    case 5:\n                        System.out.println(\"Exiting...\");\n                        break;\n\n                    default:\n                        System.out.println(\"Invalid Choice\");\n                }\n\n            } while(choice != 5);\n\n            con.close();\n        }\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}"},{"id":5,"q1":"/*Write a program to accept roll no. Marks from users. Throw user defined exception\nMarks out of Bound if marks are 100.*/\n\npackage ExceptionHandling;\n\nimport java.util.Scanner;\n\n// Custom Exception\nclass MarksOutOfBound extends Exception {\n    MarksOutOfBound(String msg) {\n        super(msg);\n    }\n}\n\npublic class Excep {\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n\n        int rollNo, marks;\n\n        System.out.print(\"Enter Roll No: \");\n        rollNo = sc.nextInt();\n\n        System.out.print(\"Enter Marks: \");\n        marks = sc.nextInt();\n\n        try {\n            if (marks > 100) {\n                throw new MarksOutOfBound(\"Marks should not be more than 100\");\n            }\n\n            System.out.println(\"Roll No: \" + rollNo);\n            System.out.println(\"Marks: \" + marks);\n\n        } catch (MarksOutOfBound e) {\n            System.out.println(\"Exception: \" + e.getMessage());\n        }\n\n        sc.close();\n    }\n}\n\n","q2":"/*Implement a Java program to manage a library system using OOP concepts such as\nclasses, inheritance, encapsulation, and polymorphism. Include features like adding\nbooks, issuing books, returning books, and checking availability.*/\n\n\nimport java.util.Scanner;\n\nclass Book\n{\n    int id;\n    String name;\n    String author;\n    boolean available = true;\n\n    void addBook()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Book ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Book Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Author Name:\");\n        author = sc.nextLine();\n    }\n\n    void displayBook()\n    {\n        System.out.println(\"\\nBook ID: \" + id);\n        System.out.println(\"Book Name: \" + name);\n        System.out.println(\"Author: \" + author);\n\n        if(available)\n            System.out.println(\"Status: Available\");\n        else\n            System.out.println(\"Status: Issued\");\n    }\n}\n\nclass Library extends Book\n{\n    // Polymorphism (Method Overriding)\n    void displayBook()\n    {\n        super.displayBook();\n\n        if(available)\n            System.out.println(\"Book can be issued.\");\n        else\n            System.out.println(\"Book is currently not available.\");\n    }\n}\n\npublic class LibraryManagementSystem\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Library books[] = new Library[10];\n\n        int count = 0;\n        int choice;\n\n        do\n        {\n            System.out.println(\"\\n===== LIBRARY MENU =====\");\n\n            System.out.println(\"1. Add Book\");\n            System.out.println(\"2. Display All Books\");\n            System.out.println(\"3. Issue Book\");\n            System.out.println(\"4. Return Book\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n\n                    books[count] = new Library();\n\n                    books[count].addBook();\n\n                    count++;\n\n                    System.out.println(\"Book Added Successfully.\");\n                    break;\n\n                case 2:\n\n                    if(count == 0)\n                    {\n                        System.out.println(\"No Books Available.\");\n                    }\n                    else\n                    {\n                        for(int i = 0; i < count; i++)\n                        {\n                            books[i].displayBook();\n                        }\n                    }\n\n                    break;\n\n                case 3:\n\n                    System.out.println(\"Enter Book ID to Issue:\");\n                    int issueId = sc.nextInt();\n\n                    boolean foundIssue = false;\n\n                    for(int i = 0; i < count; i++)\n                    {\n                        if(books[i].id == issueId)\n                        {\n                            foundIssue = true;\n\n                            if(books[i].available)\n                            {\n                                books[i].available = false;\n\n                                System.out.println(\n                                \"Book Issued Successfully.\");\n                            }\n                            else\n                            {\n                                System.out.println(\n                                \"Book Already Issued.\");\n                            }\n                        }\n                    }\n\n                    if(!foundIssue)\n                    {\n                        System.out.println(\"Book Not Found.\");\n                    }\n\n                    break;\n\n                case 4:\n\n                    System.out.println(\"Enter Book ID to Return:\");\n                    int returnId = sc.nextInt();\n\n                    boolean foundReturn = false;\n\n                    for(int i = 0; i < count; i++)\n                    {\n                        if(books[i].id == returnId)\n                        {\n                            foundReturn = true;\n\n                            if(!books[i].available)\n                            {\n                                books[i].available = true;\n\n                                System.out.println(\n                                \"Book Returned Successfully.\");\n                            }\n                            else\n                            {\n                                System.out.println(\n                                \"Book is Already Available.\");\n                            }\n                        }\n                    }\n\n                    if(!foundReturn)\n                    {\n                        System.out.println(\"Book Not Found.\");\n                    }\n\n                    break;\n\n                case 5:\n\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}"},{"id":6,"q1":"/* Create a Java program to model an academic institution using OOP concepts like\ninheritance, encapsulation, and polymorphism. Define a class hierarchy as follows:\nStaff → Professor → Head of Department (HOD).\nA. Staff: Store and display staff name, date of joining, and staff ID.\nB. Professor: Inherit all Staff details and additionally display subject\nspecialization and salary.\nC. HOD: Inherit all Professor details and additionally display department\nallowance (if applicable).\n*/\n\nimport java.util.Scanner;\n\nclass Staff\n{\n    int id;\n    String name, doj;\n\n    void getStaff()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Staff ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Staff Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Date of Joining:\");\n        doj = sc.nextLine();\n    }\n\n    void displayStaff()\n    {\n        System.out.println(\"\\n----- STAFF DETAILS -----\");\n\n        System.out.println(\"Staff ID: \" + id);\n        System.out.println(\"Staff Name: \" + name);\n        System.out.println(\"Date of Joining: \" + doj);\n    }\n}\n\nclass Professor extends Staff\n{\n    String subject;\n    double salary;\n\n    void getProfessor()\n    {\n        getStaff();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Subject Specialization:\");\n        subject = sc.nextLine();\n\n        System.out.println(\"Enter Salary:\");\n        salary = sc.nextDouble();\n    }\n\n    void displayProfessor()\n    {\n        displayStaff();\n\n        System.out.println(\n        \"\\n----- PROFESSOR DETAILS -----\");\n\n        System.out.println(\"Subject: \" + subject);\n        System.out.println(\"Salary: \" + salary);\n    }\n}\n\nclass HOD extends Professor\n{\n    double allowance;\n\n    void getHOD()\n    {\n        getProfessor();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Department Allowance:\");\n        allowance = sc.nextDouble();\n    }\n\n    void displayHOD()\n    {\n        displayProfessor();\n\n        System.out.println(\n        \"\\n----- HOD DETAILS -----\");\n\n        System.out.println(\n        \"Department Allowance: \" + allowance);\n    }\n}\n\npublic class AcademicInstitution\n{\n    public static void main(String args[])\n    {\n        HOD h = new HOD();\n\n        h.getHOD();\n\n        h.displayHOD();\n    }\n}","q2":"/*Write a program of servlet to demonstrate GET and POST Methods with suitable\nexample using simulation.*/\n\n\nimport java.util.Scanner;\n\npublic class RequestSimulator {\n\n    // Simulating GET method\n    public static void doGet(String name, String age) {\n        System.out.println(\"\\n--- GET Method Execution ---\");\n        System.out.println(\"URL: http://localhost:8080/student?name=\" + name +\n                \"&age=\" + age);\n\n        System.out.println(\"Data received using GET method:\");\n        System.out.println(\"Name: \" + name);\n        System.out.println(\"Age: \" + age);\n    }\n\n    // Simulating POST method\n    public static void doPost(String name, String age) {\n        System.out.println(\"\\n--- POST Method Execution ---\");\n        System.out.println(\"URL: http://localhost:8080/student\");\n        System.out.println(\"(Data is sent in request body, not visible in URL)\");\n\n        System.out.println(\"Data received using POST method:\");\n        System.out.println(\"Name: \" + name);\n        System.out.println(\"Age: \" + age);\n    }\n\n    public static void main(String[] args) {\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"=== Servlet GET/POST Simulation ===\");\n\n        // Taking input\n        System.out.print(\"Enter Name: \");\n        String name = sc.nextLine();\n\n        System.out.print(\"Enter Age: \");\n        String age = sc.nextLine();\n\n        // Choosing method\n        System.out.println(\"\\nChoose Method:\");\n        System.out.println(\"1. GET\");\n        System.out.println(\"2. POST\");\n        System.out.print(\"Enter choice: \");\n\n        int choice = sc.nextInt();\n\n        // Calling respective method\n        if (choice == 1) {\n            doGet(name, age);\n        } else if (choice == 2) {\n            doPost(name, age);\n        } else {\n            System.out.println(\"Invalid choice!\");\n        }\n\n        sc.close();\n    }\n}"},{"id":7,"q1":"/*Implement a Java Program for multithreading (Synchronization): Create thread for\nWithdraw & Deposit tasks for Bank Account, display the current balance also.*/\n\n// Java Program for Multithreading with Synchronization\n// Bank Account Deposit and Withdraw Example\n\nclass BankAccount {\n    private int balance = 1000; // Initial Balance\n\n    // Synchronized method for deposit\n    public synchronized void deposit(int amount) {\n        System.out.println(\"Depositing Amount: \" + amount);\n\n        balance = balance + amount;\n\n        System.out.println(\"Amount Deposited Successfully\");\n        System.out.println(\"Current Balance after Deposit: \" + balance);\n        System.out.println(\"--------------------------------\");\n    }\n\n    // Synchronized method for withdraw\n    public synchronized void withdraw(int amount) {\n        System.out.println(\"Withdrawing Amount: \" + amount);\n\n        if (balance >= amount) {\n            balance = balance - amount;\n\n            System.out.println(\"Amount Withdrawn Successfully\");\n            System.out.println(\"Current Balance after Withdrawal: \" + balance);\n        } else {\n            System.out.println(\"Insufficient Balance\");\n            System.out.println(\"Current Balance: \" + balance);\n        }\n\n        System.out.println(\"--------------------------------\");\n    }\n\n    // Method to display current balance\n    public synchronized void displayBalance() {\n        System.out.println(\"Final Current Balance: \" + balance);\n    }\n}\n\n// Deposit Thread\nclass DepositThread extends Thread {\n    BankAccount account;\n\n    DepositThread(BankAccount account) {\n        this.account = account;\n    }\n\n    public void run() {\n        account.deposit(500);\n    }\n}\n\n// Withdraw Thread\nclass WithdrawThread extends Thread {\n    BankAccount account;\n\n    WithdrawThread(BankAccount account) {\n        this.account = account;\n    }\n\n    public void run() {\n        account.withdraw(700);\n    }\n}\n\n// Main Class\npublic class BankSynchronization {\n    public static void main(String[] args) {\n\n        BankAccount account = new BankAccount();\n\n        // Creating Threads\n        DepositThread t1 = new DepositThread(account);\n        WithdrawThread t2 = new WithdrawThread(account);\n\n        // Starting Threads\n        t1.start();\n        t2.start();\n\n        // Waiting for threads to complete\n        try {\n            t1.join();\n            t2.join();\n        } catch (InterruptedException e) {\n            System.out.println(e);\n        }\n\n        // Display Final Balance\n        account.displayBalance();\n    }\n}\n","q2":"/*Write a program to demonstrate how the process tasks asynchronously in a Spring\nBoot application.*/\n\n/* 1.go to start.spring.import \n2.download file \n3.open the file in intellij and run the application\n4.go to src/main/java/com/example/demo/DemoApplication.java\n5.create class AsyncService,AsyncController,AsyncDemoApplication */\n\n/* ADD code in AsyncDemoApplication.java */\npackage com.example.firstdemo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.scheduling.annotation.EnableAsync;\n\n@SpringBootApplication\n@EnableAsync\npublic class AsyncDemoApplication {\n    public static void main (String[] args) {\n        SpringApplication.run(AsyncDemoApplication.class, args);\n    }\n\n}\n\n\n/* Add code in AsyncService.java */\npackage com.example.firstdemo;\n\nimport org.springframework.scheduling.annotation.Async;\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class AsyncService {\n\n    @Async\n    public void processTask() {\n        try {\n            System.out.println(\"Task started on thread: \" +\n                    Thread.currentThread().getName());\n\n            Thread.sleep(5000); // simulate long process (5 seconds)\n\n            System.out.println(\"Task completed on thread:\" +\n                    Thread.currentThread().getName());\n\n        } catch (InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n/* Add code in AsyncController.java */\npackage com.example.firstdemo;\n\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.RestController;\n\n@RestController\npublic class AsyncController {\n\n    @Autowired\n    private AsyncService asyncService;\n\n    @GetMapping(\"/run\")\n    public String runTask() {\n        asyncService.processTask();\n        return \"Task triggered successfully\";\n    }\n}"},{"id":8,"q1":"/* Implement a Java program to manage bank accounts using object-oriented\nprogramming (OOP) concepts like classes, inheritance, encapsulation, and\npolymorphism. Include features like account creation, deposit, withdrawal, and\nbalance inquiry.\n*/\n\nimport java.util.Scanner;\n\nclass Account\n{\n    int accNo;\n    String name;\n    double balance;\n\n    void createAccount()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Account Number:\");\n        accNo = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Account Holder Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Initial Balance:\");\n        balance = sc.nextDouble();\n\n        System.out.println(\"Account Created Successfully.\");\n    }\n\n    void display()\n    {\n        System.out.println(\"\\nAccount Number: \" + accNo);\n        System.out.println(\"Account Holder Name: \" + name);\n        System.out.println(\"Balance: \" + balance);\n    }\n}\n\nclass Bank extends Account\n{\n    void deposit()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Amount to Deposit:\");\n        double amt = sc.nextDouble();\n\n        balance = balance + amt;\n\n        System.out.println(\"Amount Deposited Successfully.\");\n    }\n\n    void withdraw()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Amount to Withdraw:\");\n        double amt = sc.nextDouble();\n\n        if(balance >= amt)\n        {\n            balance = balance - amt;\n\n            System.out.println(\"Amount Withdrawn Successfully.\");\n        }\n        else\n        {\n            System.out.println(\"Insufficient Balance.\");\n        }\n    }\n\n    // Polymorphism (Method Overriding)\n    void display()\n    {\n        super.display();\n\n        System.out.println(\"Thank You for Banking.\");\n    }\n}\n\npublic class BankManagementSystem\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Bank b = new Bank();\n\n        int choice;\n\n        do\n        {\n            System.out.println(\"\\n===== BANK MENU =====\");\n\n            System.out.println(\"1. Create Account\");\n            System.out.println(\"2. Deposit\");\n            System.out.println(\"3. Withdraw\");\n            System.out.println(\"4. Balance Inquiry\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n                    b.createAccount();\n                    break;\n\n                case 2:\n                    b.deposit();\n                    break;\n\n                case 3:\n                    b.withdraw();\n                    break;\n\n                case 4:\n                    b.display();\n                    break;\n\n                case 5:\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}","q2":"/*Write a program to demonstrate how the process tasks asynchronously in a Spring\nBoot application.*/\n\n/* 1.go to start.spring.import \n2.download file \n3.open the file in intellij and run the application\n4.go to src/main/java/com/example/demo/DemoApplication.java\n5.create class AsyncService,AsyncController,AsyncDemoApplication */\n\n/* ADD code in AsyncDemoApplication.java */\npackage com.example.firstdemo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.scheduling.annotation.EnableAsync;\n\n@SpringBootApplication\n@EnableAsync\npublic class AsyncDemoApplication {\n    public static void main (String[] args) {\n        SpringApplication.run(AsyncDemoApplication.class, args);\n    }\n\n}\n\n\n/* Add code in AsyncService.java */\npackage com.example.firstdemo;\n\nimport org.springframework.scheduling.annotation.Async;\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class AsyncService {\n\n    @Async\n    public void processTask() {\n        try {\n            System.out.println(\"Task started on thread: \" +\n                    Thread.currentThread().getName());\n\n            Thread.sleep(5000); // simulate long process (5 seconds)\n\n            System.out.println(\"Task completed on thread:\" +\n                    Thread.currentThread().getName());\n\n        } catch (InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n/* Add code in AsyncController.java */\npackage com.example.firstdemo;\n\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.RestController;\n\n@RestController\npublic class AsyncController {\n\n    @Autowired\n    private AsyncService asyncService;\n\n    @GetMapping(\"/run\")\n    public String runTask() {\n        asyncService.processTask();\n        return \"Task triggered successfully\";\n    }\n}"},{"id":9,"q1":"/* Develop a Java-based library management application that demonstrates OOP\nprinciples and uses exception handling to handle cases like issuing books, returning\nbooks, etc.\n*/\n\nimport java.util.Scanner;\n\nclass Book\n{\n    int id;\n    String name, author;\n    boolean available = true;\n\n    void addBook()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Book ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Book Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Author Name:\");\n        author = sc.nextLine();\n    }\n\n    void display()\n    {\n        System.out.println(\"\\nBook ID: \" + id);\n        System.out.println(\"Book Name: \" + name);\n        System.out.println(\"Author Name: \" + author);\n\n        if(available)\n            System.out.println(\"Status: Available\");\n        else\n            System.out.println(\"Status: Issued\");\n    }\n}\n\nclass Library extends Book\n{\n    // Polymorphism (Method Overriding)\n    void display()\n    {\n        super.display();\n\n        if(available)\n            System.out.println(\"Book can be issued.\");\n        else\n            System.out.println(\"Book is not available.\");\n    }\n}\n\npublic class LibraryManagement\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Library b[] = new Library[10];\n\n        int count = 0, choice;\n\n        do\n        {\n            System.out.println(\"\\n===== LIBRARY MENU =====\");\n\n            System.out.println(\"1. Add Book\");\n            System.out.println(\"2. Display Books\");\n            System.out.println(\"3. Issue Book\");\n            System.out.println(\"4. Return Book\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n\n                    b[count] = new Library();\n\n                    b[count].addBook();\n\n                    count++;\n\n                    System.out.println(\"Book Added.\");\n                    break;\n\n                case 2:\n\n                    if(count == 0)\n                    {\n                        System.out.println(\"No Books Found.\");\n                    }\n                    else\n                    {\n                        for(int i=0; i<count; i++)\n                        {\n                            b[i].display();\n                        }\n                    }\n\n                    break;\n\n                case 3:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Issue:\");\n\n                        int issueId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == issueId)\n                            {\n                                found = true;\n\n                                if(b[i].available)\n                                {\n                                    b[i].available = false;\n\n                                    System.out.println(\n                                            \"Book Issued Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \" Exception : Book Already Issued.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 4:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Return:\");\n\n                        int returnId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == returnId)\n                            {\n                                found = true;\n\n                                if(!b[i].available)\n                                {\n                                    b[i].available = true;\n\n                                    System.out.println(\n                                            \"Book Returned Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \"Exception : Book Already Returned.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 5:\n\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}","q2":"/*Write a client-server program using TCP sockets to echo the message sent by the\nclient.*/\n\n\n//Server code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoServer {\n    public static void main(String[] args) {\n        int port = 1234;\n\n        try (ServerSocket serverSocket = new ServerSocket(port)) {\n            System.out.println(\"Server is running and waiting for client...\");\n\n            Socket socket = serverSocket.accept();\n            System.out.println(\"Client connected!\");\n\n            BufferedReader input = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while ((message = input.readLine()) != null) {\n                System.out.println(\"Client says: \" + message);\n\n                // Echo back to client\n                output.println(\"Echo: \" + message);\n\n                if (message.equalsIgnoreCase(\"exit\")) {\n                    break;\n                }\n            }\n\n            socket.close();\n            System.out.println(\"Connection closed.\");\n\n        } catch (IOException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n//Client Code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoClient \n{\n    public static void main(String[] args) \n\t{\n        String host = \"localhost\";\n        int port = 1234;\n\n        try (Socket socket = new Socket(host, port)) \n\t\t{\n            System.out.println(\"Connected to server!\");\n\n            BufferedReader userInput = new BufferedReader(\n                    new InputStreamReader(System.in));\n            BufferedReader serverInput = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while (true) \n\t\t\t{\n                System.out.print(\"Enter message: \");\n                message = userInput.readLine();\n\n                output.println(message);\n\n                String response = serverInput.readLine();\n                System.out.println(\"Server replied: \" + response);\n\n                if (message.equalsIgnoreCase(\"exit\"))\n\t\t\t\t{\n                    break;\n                }\n            }\n\n            socket.close();\n\n        } catch (IOException e) \n\t\t{\n            e.printStackTrace();\n        }\n    }\n}\n"},{"id":10,"q1":"/*Implement a Java program to manage retail staff using OOP concepts. Define a\nhierarchy: Worker → Supervisor → StoreManager.\nA. Worker: Store and display worker name, ID, and date of birth.\nB. Supervisor: Inherit Worker details and additionally include monthly salary.\nC. StoreManager: Inherit Supervisor details and additionally include\nprofit-based incentives or commission (if applicable).\n*/\n\nimport java.util.Scanner;\n\nclass Worker\n{\n    int id;\n    String name, dob;\n\n    void getWorker()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Worker ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Worker Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Date of Birth:\");\n        dob = sc.nextLine();\n    }\n\n    void displayWorker()\n    {\n        System.out.println(\"\\n----- WORKER DETAILS -----\");\n\n        System.out.println(\"Worker ID: \" + id);\n        System.out.println(\"Worker Name: \" + name);\n        System.out.println(\"Date of Birth: \" + dob);\n    }\n}\n\nclass Supervisor extends Worker\n{\n    double salary;\n\n    void getSupervisor()\n    {\n        getWorker();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Monthly Salary:\");\n        salary = sc.nextDouble();\n    }\n\n    void displaySupervisor()\n    {\n        displayWorker();\n\n        System.out.println(\"\\n----- SUPERVISOR DETAILS -----\");\n\n        System.out.println(\"Monthly Salary: \" + salary);\n    }\n}\n\nclass StoreManager extends Supervisor\n{\n    double incentive;\n\n    void getStoreManager()\n    {\n        getSupervisor();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Incentive/Commission:\");\n        incentive = sc.nextDouble();\n    }\n\n    void displayStoreManager()\n    {\n        displaySupervisor();\n\n        System.out.println(\n                \"\\n----- STORE MANAGER DETAILS -----\");\n\n        System.out.println(\n                \"Incentive/Commission: \" + incentive);\n    }\n}\n\npublic class RetailStaffManagement\n{\n    public static void main(String args[])\n    {\n        StoreManager s = new StoreManager();\n\n        s.getStoreManager();\n\n        s.displayStoreManager();\n    }\n}","q2":"/*Write a client-server program using TCP sockets to echo the message sent by the\nclient.*/\n\n\n//Server code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoServer {\n    public static void main(String[] args) {\n        int port = 1234;\n\n        try (ServerSocket serverSocket = new ServerSocket(port)) {\n            System.out.println(\"Server is running and waiting for client...\");\n\n            Socket socket = serverSocket.accept();\n            System.out.println(\"Client connected!\");\n\n            BufferedReader input = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while ((message = input.readLine()) != null) {\n                System.out.println(\"Client says: \" + message);\n\n                // Echo back to client\n                output.println(\"Echo: \" + message);\n\n                if (message.equalsIgnoreCase(\"exit\")) {\n                    break;\n                }\n            }\n\n            socket.close();\n            System.out.println(\"Connection closed.\");\n\n        } catch (IOException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n//Client Code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoClient \n{\n    public static void main(String[] args) \n\t{\n        String host = \"localhost\";\n        int port = 1234;\n\n        try (Socket socket = new Socket(host, port)) \n\t\t{\n            System.out.println(\"Connected to server!\");\n\n            BufferedReader userInput = new BufferedReader(\n                    new InputStreamReader(System.in));\n            BufferedReader serverInput = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while (true) \n\t\t\t{\n                System.out.print(\"Enter message: \");\n                message = userInput.readLine();\n\n                output.println(message);\n\n                String response = serverInput.readLine();\n                System.out.println(\"Server replied: \" + response);\n\n                if (message.equalsIgnoreCase(\"exit\"))\n\t\t\t\t{\n                    break;\n                }\n            }\n\n            socket.close();\n\n        } catch (IOException e) \n\t\t{\n            e.printStackTrace();\n        }\n    }\n}\n"},{"id":11,"q1":"/*\nImplement a Java Program to create calculator using AWT\n*/\n\nimport java.awt.*;\nimport java.awt.event.*;\n\nclass Calculator extends Frame implements ActionListener\n{\n    Label l1, l2, l3;\n\n    TextField t1, t2, t3;\n\n    Button b1, b2, b3, b4;\n\n    Calculator()\n    {\n        l1 = new Label(\"First Number:\");\n        l2 = new Label(\"Second Number:\");\n        l3 = new Label(\"Result:\");\n\n        t1 = new TextField();\n        t2 = new TextField();\n        t3 = new TextField();\n\n        b1 = new Button(\"Add\");\n        b2 = new Button(\"Sub\");\n        b3 = new Button(\"Mul\");\n        b4 = new Button(\"Div\");\n\n        setLayout(null);\n\n        l1.setBounds(50, 50, 100, 30);\n        t1.setBounds(170, 50, 100, 30);\n\n        l2.setBounds(50, 100, 100, 30);\n        t2.setBounds(170, 100, 100, 30);\n\n        l3.setBounds(50, 150, 100, 30);\n        t3.setBounds(170, 150, 100, 30);\n\n        b1.setBounds(50, 220, 50, 30);\n        b2.setBounds(120, 220, 50, 30);\n        b3.setBounds(190, 220, 50, 30);\n        b4.setBounds(260, 220, 50, 30);\n\n        add(l1);\n        add(t1);\n\n        add(l2);\n        add(t2);\n\n        add(l3);\n        add(t3);\n\n        add(b1);\n        add(b2);\n        add(b3);\n        add(b4);\n\n        b1.addActionListener(this);\n        b2.addActionListener(this);\n        b3.addActionListener(this);\n        b4.addActionListener(this);\n\n        setSize(400, 350);\n\n        setVisible(true);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        int a = Integer.parseInt(t1.getText());\n\n        int b = Integer.parseInt(t2.getText());\n\n        int result = 0;\n\n        if(e.getSource() == b1)\n        {\n            result = a + b;\n        }\n\n        if(e.getSource() == b2)\n        {\n            result = a - b;\n        }\n\n        if(e.getSource() == b3)\n        {\n            result = a * b;\n        }\n\n        if(e.getSource() == b4)\n        {\n            result = a / b;\n        }\n\n        t3.setText(String.valueOf(result));\n    }\n\n    public static void main(String args[])\n    {\n        new Calculator();\n    }\n}","q2":"/*Write a program to implement student information in a file and perform the file\noperations on it.*/\n\n\n//Create \n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass CreateStudentFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File file = new File(\"student.txt\");\n\n            if(file.createNewFile())\n            {\n                System.out.println(\"File Created\");\n            }\n\n            Scanner sc = new Scanner(System.in);\n\n            System.out.println(\"Enter Roll Number:\");\n            int roll = sc.nextInt();\n            sc.nextLine();\n\n            // Check Duplicate Roll No\n            boolean exists = false;\n\n            Scanner reader = new Scanner(file);\n\n            while(reader.hasNextLine())\n            {\n                String line = reader.nextLine();\n\n                if(line.startsWith(\"Roll No:\"))\n                {\n                    int r = Integer.parseInt(\n                            line.substring(8).trim());\n\n                    if(r == roll)\n                    {\n                        exists = true;\n                        break;\n                    }\n                }\n            }\n\n            reader.close();\n\n            if(exists)\n            {\n                System.out.println(\n                \"Roll Number Already Exists\");\n            }\n            else\n            {\n                FileWriter writer =\n                new FileWriter(file, true);\n\n                System.out.println(\n                \"Enter Student Name:\");\n                String name = sc.nextLine();\n\n                System.out.println(\"Enter Marks:\");\n                int marks = sc.nextInt();\n\n                writer.write(\n                \"\\nRoll No: \" + roll + \"\\n\");\n\n                writer.write(\n                \"Name: \" + name + \"\\n\");\n\n                writer.write(\n                \"Marks: \" + marks + \"\\n\");\n\n                writer.close();\n\n                System.out.println(\n                \"Student Record Added\");\n            }\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n\n//Read\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass ReadStudentFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File file = new File(\"student.txt\");\n\n            Scanner reader =\n            new Scanner(file);\n\n            System.out.println(\n            \"\\n----- STUDENT RECORDS -----\");\n\n            while(reader.hasNextLine())\n            {\n                System.out.println(\n                reader.nextLine());\n            }\n\n            reader.close();\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n\n//Delete\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass DeleteStudentFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File inputFile =\n            new File(\"student.txt\");\n\n            File tempFile =\n            new File(\"temp.txt\");\n\n            BufferedReader br =\n            new BufferedReader(\n            new FileReader(inputFile));\n\n            BufferedWriter bw =\n            new BufferedWriter(\n            new FileWriter(tempFile));\n\n            Scanner sc =\n            new Scanner(System.in);\n\n            System.out.println(\n            \"Enter Roll Number to Delete:\");\n\n            int deleteRoll = sc.nextInt();\n\n            String line;\n\n            while((line = br.readLine()) != null)\n            {\n                if(line.startsWith(\"Roll No:\"))\n                {\n                    int roll =\n                    Integer.parseInt(\n                    line.substring(8).trim());\n\n                    String name =\n                    br.readLine();\n\n                    String marks =\n                    br.readLine();\n\n                    if(roll != deleteRoll)\n                    {\n                        bw.write(line);\n                        bw.newLine();\n\n                        bw.write(name);\n                        bw.newLine();\n\n                        bw.write(marks);\n                        bw.newLine();\n                    }\n                }\n            }\n\n            br.close();\n            bw.close();\n\n            inputFile.delete();\n\n            tempFile.renameTo(inputFile);\n\n            System.out.println(\n            \"Record Deleted\");\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n//Update\n\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass UpdateStudentFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File inputFile =\n            new File(\"student.txt\");\n\n            File tempFile =\n            new File(\"temp.txt\");\n\n            BufferedReader br =\n            new BufferedReader(\n            new FileReader(inputFile));\n\n            BufferedWriter bw =\n            new BufferedWriter(\n            new FileWriter(tempFile));\n\n            Scanner sc =\n            new Scanner(System.in);\n\n            System.out.println(\n            \"Enter Roll Number to Update:\");\n\n            int updateRoll = sc.nextInt();\n            sc.nextLine();\n\n            String line;\n\n            boolean found = false;\n\n            while((line = br.readLine()) != null)\n            {\n                if(line.startsWith(\"Roll No:\"))\n                {\n                    int roll =\n                    Integer.parseInt(\n                    line.substring(8).trim());\n\n                    if(roll == updateRoll)\n                    {\n                        found = true;\n\n                        // Skip old data\n                        br.readLine();\n                        br.readLine();\n\n                        System.out.println(\n                        \"Enter New Name:\");\n\n                        String name =\n                        sc.nextLine();\n\n                        System.out.println(\n                        \"Enter New Marks:\");\n\n                        int marks =\n                        sc.nextInt();\n\n                        bw.write(\n                        \"Roll No: \" + roll);\n\n                        bw.newLine();\n\n                        bw.write(\n                        \"Name: \" + name);\n\n                        bw.newLine();\n\n                        bw.write(\n                        \"Marks: \" + marks);\n\n                        bw.newLine();\n                    }\n\n                    else\n                    {\n                        bw.write(line);\n                        bw.newLine();\n\n                        bw.write(br.readLine());\n                        bw.newLine();\n\n                        bw.write(br.readLine());\n                        bw.newLine();\n                    }\n                }\n            }\n\n            br.close();\n            bw.close();\n\n            inputFile.delete();\n\n            tempFile.renameTo(inputFile);\n\n            if(found)\n                System.out.println(\n                \"Record Updated\");\n\n            else\n                System.out.println(\n                \"Student Not Found\");\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}"},{"id":12,"q1":"/*Write a program to accept roll no. Marks from users. Throw user defined exception\nMarks out of Bound if marks are 100.*/\n\npackage ExceptionHandling;\n\nimport java.util.Scanner;\n\n// Custom Exception\nclass MarksOutOfBound extends Exception {\n    MarksOutOfBound(String msg) {\n        super(msg);\n    }\n}\n\npublic class Excep {\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n\n        int rollNo, marks;\n\n        System.out.print(\"Enter Roll No: \");\n        rollNo = sc.nextInt();\n\n        System.out.print(\"Enter Marks: \");\n        marks = sc.nextInt();\n\n        try {\n            if (marks > 100) {\n                throw new MarksOutOfBound(\"Marks should not be more than 100\");\n            }\n\n            System.out.println(\"Roll No: \" + rollNo);\n            System.out.println(\"Marks: \" + marks);\n\n        } catch (MarksOutOfBound e) {\n            System.out.println(\"Exception: \" + e.getMessage());\n        }\n\n        sc.close();\n    }\n}\n\n","q2":"/*\nCreate a Java application that connects to a MySQL database to manage employee\ninformation. Implement functionalities like adding, updating, deleting, and viewing\nemployee records using JDBC. Use prepared statements to prevent SQL injection\nand handle exceptions gracefully.\n\nTable :\n\nCREATE TABLE employee(\nid int primary key auto_increment,\nname varchar(100),\nsalary double,\ndepartment varchar(100));\n*/\n\n\n\npackage JAVAJDBC;\nimport java.sql.*;\nimport java.util.Scanner;\n\npublic class EmployeeApp {\n\n    static final String URL = \"jdbc:mysql://localhost:3306/company\";\n    static final String USER = \"root\";\n    static final String PASSWORD = \"@zekky@999\";\n\n    public static void main(String[] args) {\n\n        Scanner sc = new Scanner(System.in);\n\n        try {\n            Connection conn = DriverManager.getConnection(URL, USER, PASSWORD);\n\n            while (true) {\n                System.out.println(\"\\n1. Add Employee\");\n                System.out.println(\"2. View Employees\");\n                System.out.println(\"3. Update Employee\");\n                System.out.println(\"4. Delete Employee\");\n                System.out.println(\"5. Exit\");\n\n                System.out.print(\"Enter choice: \");\n                int choice = sc.nextInt();\n\n                switch (choice) {\n\n                    case 1:\n                        addEmployee(conn, sc);\n                        break;\n\n                    case 2:\n                        viewEmployees(conn);\n                        break;\n\n                    case 3:\n                        updateEmployee(conn, sc);\n                        break;\n\n                    case 4:\n                        deleteEmployee(conn, sc);\n                        break;\n\n                    case 5:\n                        conn.close();\n                        System.out.println(\"Exited Successfully!\");\n                        return;\n\n                    default:\n                        System.out.println(\"Invalid Choice!\");\n                }\n            }\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // ADD\n    public static void addEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"INSERT INTO employee(name, salary, department) VALUES (?, ?, ?)\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Name: \");\n            sc.nextLine();\n            String name = sc.nextLine();\n\n            System.out.print(\"Enter Salary: \");\n            double salary = sc.nextDouble();\n\n            System.out.print(\"Enter Department: \");\n            sc.nextLine();\n            String dept = sc.nextLine();\n\n            ps.setString(1, name);\n            ps.setDouble(2, salary);\n            ps.setString(3, dept);\n\n            ps.executeUpdate();\n            System.out.println(\"Employee Added!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // VIEW\n    public static void viewEmployees(Connection conn) {\n        try {\n            String sql = \"SELECT * FROM employee\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            ResultSet rs = ps.executeQuery();\n\n            System.out.println(\"\\n--- Employee List ---\");\n            while (rs.next()) {\n                System.out.println(\n                        rs.getInt(\"id\") + \" | \" +\n                                rs.getString(\"name\") + \" | \" +\n                                rs.getDouble(\"salary\") + \" | \" +\n                                rs.getString(\"department\"));\n            }\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // UPDATE\n    public static void updateEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"UPDATE employee SET salary=? WHERE id=?\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n\n            System.out.print(\"Enter New Salary: \");\n            double salary = sc.nextDouble();\n\n            ps.setDouble(1, salary);\n            ps.setInt(2, id);\n\n            int rows = ps.executeUpdate();\n\n            if (rows > 0)\n                System.out.println(\"Employee Updated!\");\n            else\n                System.out.println(\"Employee Not Found!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // DELETE\n    public static void deleteEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"DELETE FROM employee WHERE id=?\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n\n            ps.setInt(1, id);\n\n            int rows = ps.executeUpdate();\n\n            if (rows > 0)\n                System.out.println(\"Employee Deleted!\");\n            else\n                System.out.println(\"Employee Not Found!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n}\n\n"},{"id":13,"q1":"/* Develop a Java-based library management application that demonstrates OOP\nprinciples and uses exception handling to handle cases like issuing books, returning\nbooks, etc.\n*/\n\nimport java.util.Scanner;\n\nclass Book\n{\n    int id;\n    String name, author;\n    boolean available = true;\n\n    void addBook()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Book ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Book Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Author Name:\");\n        author = sc.nextLine();\n    }\n\n    void display()\n    {\n        System.out.println(\"\\nBook ID: \" + id);\n        System.out.println(\"Book Name: \" + name);\n        System.out.println(\"Author Name: \" + author);\n\n        if(available)\n            System.out.println(\"Status: Available\");\n        else\n            System.out.println(\"Status: Issued\");\n    }\n}\n\nclass Library extends Book\n{\n    // Polymorphism (Method Overriding)\n    void display()\n    {\n        super.display();\n\n        if(available)\n            System.out.println(\"Book can be issued.\");\n        else\n            System.out.println(\"Book is not available.\");\n    }\n}\n\npublic class LibraryManagement\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Library b[] = new Library[10];\n\n        int count = 0, choice;\n\n        do\n        {\n            System.out.println(\"\\n===== LIBRARY MENU =====\");\n\n            System.out.println(\"1. Add Book\");\n            System.out.println(\"2. Display Books\");\n            System.out.println(\"3. Issue Book\");\n            System.out.println(\"4. Return Book\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n\n                    b[count] = new Library();\n\n                    b[count].addBook();\n\n                    count++;\n\n                    System.out.println(\"Book Added.\");\n                    break;\n\n                case 2:\n\n                    if(count == 0)\n                    {\n                        System.out.println(\"No Books Found.\");\n                    }\n                    else\n                    {\n                        for(int i=0; i<count; i++)\n                        {\n                            b[i].display();\n                        }\n                    }\n\n                    break;\n\n                case 3:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Issue:\");\n\n                        int issueId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == issueId)\n                            {\n                                found = true;\n\n                                if(b[i].available)\n                                {\n                                    b[i].available = false;\n\n                                    System.out.println(\n                                            \"Book Issued Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \" Exception : Book Already Issued.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 4:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Return:\");\n\n                        int returnId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == returnId)\n                            {\n                                found = true;\n\n                                if(!b[i].available)\n                                {\n                                    b[i].available = true;\n\n                                    System.out.println(\n                                            \"Book Returned Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \"Exception : Book Already Returned.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 5:\n\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}","q2":"/*Write a program to design an admission enquiry for MCA student form using\nSwing.*/\n\n\nimport javax.swing.*;\nimport java.awt.*;\nimport java.awt.event.*;\n\nclass MCAAdmissionForm extends JFrame implements ActionListener\n{\n    JLabel l1, l2, l3, l4, l5, l6;\n    JTextField t1, t2, t3;\n    JRadioButton r1, r2;\n    JComboBox c1;\n    JButton b1;\n\n    MCAAdmissionForm()\n    {\n        setTitle(\"MCA Admission Enquiry Form\");\n\n        l1 = new JLabel(\"Student Name:\");\n        l2 = new JLabel(\"Mobile Number:\");\n        l3 = new JLabel(\"Email ID:\");\n        l4 = new JLabel(\"Gender:\");\n        l5 = new JLabel(\"City:\");\n        l6 = new JLabel(\"Course:\");\n\n        t1 = new JTextField();\n        t2 = new JTextField();\n        t3 = new JTextField();\n\n        r1 = new JRadioButton(\"Male\");\n        r2 = new JRadioButton(\"Female\");\n\n        ButtonGroup bg = new ButtonGroup();\n        bg.add(r1);\n        bg.add(r2);\n\n        String course[] = {\"MCA\", \"MBA\", \"MSc IT\"};\n        c1 = new JComboBox(course);\n\n        b1 = new JButton(\"Submit\");\n\n        setLayout(null);\n\n        l1.setBounds(50, 50, 120, 30);\n        t1.setBounds(180, 50, 150, 30);\n\n        l2.setBounds(50, 100, 120, 30);\n        t2.setBounds(180, 100, 150, 30);\n\n        l3.setBounds(50, 150, 120, 30);\n        t3.setBounds(180, 150, 150, 30);\n\n        l4.setBounds(50, 200, 120, 30);\n        r1.setBounds(180, 200, 80, 30);\n        r2.setBounds(260, 200, 80, 30);\n\n        l5.setBounds(50, 250, 120, 30);\n\n        String city[] = {\"Mumbai\", \"Pune\", \"Nashik\"};\n        JComboBox cityBox = new JComboBox(city);\n        cityBox.setBounds(180, 250, 150, 30);\n\n        l6.setBounds(50, 300, 120, 30);\n        c1.setBounds(180, 300, 150, 30);\n\n        b1.setBounds(150, 370, 100, 30);\n\n        add(l1);\n        add(t1);\n\n        add(l2);\n        add(t2);\n\n        add(l3);\n        add(t3);\n\n        add(l4);\n        add(r1);\n        add(r2);\n\n        add(l5);\n        add(cityBox);\n\n        add(l6);\n        add(c1);\n\n        add(b1);\n\n        b1.addActionListener(this);\n\n        setSize(450, 500);\n        setVisible(true);\n        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        JOptionPane.showMessageDialog(this,\n                \"Admission Enquiry Submitted Successfully\");\n    }\n\n    public static void main(String args[])\n    {\n        new MCAAdmissionForm();\n    }\n}"},{"id":14,"q1":"/*Implement a Java Program for developing a word counter using AWT & Swing.*/\n\nimport java.awt.*;\nimport java.awt.event.*;\nimport javax.swing.*;\n\nclass WordCounter extends JFrame implements ActionListener\n{\n    TextArea ta;\n\n    Label l1, l2;\n\n    Button b;\n\n    WordCounter()\n    {\n        ta = new TextArea();\n\n        l1 = new Label(\"Words: 0\");\n\n        l2 = new Label(\"Characters: 0\");\n\n        b = new Button(\"Count\");\n\n        setLayout(null);\n\n        ta.setBounds(50, 50, 300, 150);\n\n        b.setBounds(130, 220, 100, 30);\n\n        l1.setBounds(50, 280, 120, 30);\n\n        l2.setBounds(200, 280, 150, 30);\n\n        add(ta);\n        add(b);\n        add(l1);\n        add(l2);\n\n        b.addActionListener(this);\n\n        setTitle(\"Word Counter\");\n\n        setSize(420, 400);\n\n        setVisible(true);\n\n        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        String text = ta.getText();\n\n        int characters = text.length();\n\n        String words[] =\n                text.trim().split(\"\\\\s+\");\n\n        int wordCount = 0;\n\n        if(text.trim().isEmpty())\n        {\n            wordCount = 0;\n        }\n        else\n        {\n            wordCount = words.length;\n        }\n\n        l1.setText(\"Words: \" + wordCount);\n\n        l2.setText(\n                \"Characters: \" + characters);\n    }\n\n    public static void main(String args[])\n    {\n        new WordCounter();\n    }\n}","q2":"/*Write a client-server program using TCP sockets to echo the message sent by the\nclient.*/\n\n\n//Server code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoServer {\n    public static void main(String[] args) {\n        int port = 1234;\n\n        try (ServerSocket serverSocket = new ServerSocket(port)) {\n            System.out.println(\"Server is running and waiting for client...\");\n\n            Socket socket = serverSocket.accept();\n            System.out.println(\"Client connected!\");\n\n            BufferedReader input = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while ((message = input.readLine()) != null) {\n                System.out.println(\"Client says: \" + message);\n\n                // Echo back to client\n                output.println(\"Echo: \" + message);\n\n                if (message.equalsIgnoreCase(\"exit\")) {\n                    break;\n                }\n            }\n\n            socket.close();\n            System.out.println(\"Connection closed.\");\n\n        } catch (IOException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n//Client Code\nimport java.io.*;\nimport java.net.*;\n\npublic class EchoClient \n{\n    public static void main(String[] args) \n\t{\n        String host = \"localhost\";\n        int port = 1234;\n\n        try (Socket socket = new Socket(host, port)) \n\t\t{\n            System.out.println(\"Connected to server!\");\n\n            BufferedReader userInput = new BufferedReader(\n                    new InputStreamReader(System.in));\n            BufferedReader serverInput = new BufferedReader(\n                    new InputStreamReader(socket.getInputStream()));\n\n            PrintWriter output = new PrintWriter(\n                    socket.getOutputStream(), true);\n\n            String message;\n\n            while (true) \n\t\t\t{\n                System.out.print(\"Enter message: \");\n                message = userInput.readLine();\n\n                output.println(message);\n\n                String response = serverInput.readLine();\n                System.out.println(\"Server replied: \" + response);\n\n                if (message.equalsIgnoreCase(\"exit\"))\n\t\t\t\t{\n                    break;\n                }\n            }\n\n            socket.close();\n\n        } catch (IOException e) \n\t\t{\n            e.printStackTrace();\n        }\n    }\n}\n"},{"id":15,"q1":"/*Implement a Java Program for multithreading (Synchronization): Create thread for\nWithdraw & Deposit tasks for Bank Account, display the current balance also.*/\n\n// Java Program for Multithreading with Synchronization\n// Bank Account Deposit and Withdraw Example\n\nclass BankAccount {\n    private int balance = 1000; // Initial Balance\n\n    // Synchronized method for deposit\n    public synchronized void deposit(int amount) {\n        System.out.println(\"Depositing Amount: \" + amount);\n\n        balance = balance + amount;\n\n        System.out.println(\"Amount Deposited Successfully\");\n        System.out.println(\"Current Balance after Deposit: \" + balance);\n        System.out.println(\"--------------------------------\");\n    }\n\n    // Synchronized method for withdraw\n    public synchronized void withdraw(int amount) {\n        System.out.println(\"Withdrawing Amount: \" + amount);\n\n        if (balance >= amount) {\n            balance = balance - amount;\n\n            System.out.println(\"Amount Withdrawn Successfully\");\n            System.out.println(\"Current Balance after Withdrawal: \" + balance);\n        } else {\n            System.out.println(\"Insufficient Balance\");\n            System.out.println(\"Current Balance: \" + balance);\n        }\n\n        System.out.println(\"--------------------------------\");\n    }\n\n    // Method to display current balance\n    public synchronized void displayBalance() {\n        System.out.println(\"Final Current Balance: \" + balance);\n    }\n}\n\n// Deposit Thread\nclass DepositThread extends Thread {\n    BankAccount account;\n\n    DepositThread(BankAccount account) {\n        this.account = account;\n    }\n\n    public void run() {\n        account.deposit(500);\n    }\n}\n\n// Withdraw Thread\nclass WithdrawThread extends Thread {\n    BankAccount account;\n\n    WithdrawThread(BankAccount account) {\n        this.account = account;\n    }\n\n    public void run() {\n        account.withdraw(700);\n    }\n}\n\n// Main Class\npublic class BankSynchronization {\n    public static void main(String[] args) {\n\n        BankAccount account = new BankAccount();\n\n        // Creating Threads\n        DepositThread t1 = new DepositThread(account);\n        WithdrawThread t2 = new WithdrawThread(account);\n\n        // Starting Threads\n        t1.start();\n        t2.start();\n\n        // Waiting for threads to complete\n        try {\n            t1.join();\n            t2.join();\n        } catch (InterruptedException e) {\n            System.out.println(e);\n        }\n\n        // Display Final Balance\n        account.displayBalance();\n    }\n}\n","q2":"/*Write a program to demonstrate how the process tasks asynchronously in a Spring\nBoot application.*/\n\n/* 1.go to start.spring.import \n2.download file \n3.open the file in intellij and run the application\n4.go to src/main/java/com/example/demo/DemoApplication.java\n5.create class AsyncService,AsyncController,AsyncDemoApplication */\n\n/* ADD code in AsyncDemoApplication.java */\npackage com.example.firstdemo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.scheduling.annotation.EnableAsync;\n\n@SpringBootApplication\n@EnableAsync\npublic class AsyncDemoApplication {\n    public static void main (String[] args) {\n        SpringApplication.run(AsyncDemoApplication.class, args);\n    }\n\n}\n\n\n/* Add code in AsyncService.java */\npackage com.example.firstdemo;\n\nimport org.springframework.scheduling.annotation.Async;\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class AsyncService {\n\n    @Async\n    public void processTask() {\n        try {\n            System.out.println(\"Task started on thread: \" +\n                    Thread.currentThread().getName());\n\n            Thread.sleep(5000); // simulate long process (5 seconds)\n\n            System.out.println(\"Task completed on thread:\" +\n                    Thread.currentThread().getName());\n\n        } catch (InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n/* Add code in AsyncController.java */\npackage com.example.firstdemo;\n\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.RestController;\n\n@RestController\npublic class AsyncController {\n\n    @Autowired\n    private AsyncService asyncService;\n\n    @GetMapping(\"/run\")\n    public String runTask() {\n        asyncService.processTask();\n        return \"Task triggered successfully\";\n    }\n}"},{"id":16,"q1":"/*Create a hierarchy of Employee, Manager, Sales Manager, they should have the\nfollowing functionality:\nA. Employee: Display name, date of birth and id of Employee.\nB. Manager: Display all above information with salary drawn.\nC. Sales Manager: Display all above information and commission if applicable. */\n\n\n   import java.util.Scanner;\n\nclass Employee\n{\n    int id;\n    String name, dob;\n\n    void getEmployee()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Employee ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Employee Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Date of Birth:\");\n        dob = sc.nextLine();\n    }\n\n    void displayEmployee()\n    {\n        System.out.println(\"\\n----- EMPLOYEE DETAILS -----\");\n\n        System.out.println(\"Employee ID: \" + id);\n        System.out.println(\"Employee Name: \" + name);\n        System.out.println(\"Date of Birth: \" + dob);\n    }\n}\n\nclass Manager extends Employee\n{\n    double salary;\n\n    void getManager()\n    {\n        getEmployee();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Salary:\");\n        salary = sc.nextDouble();\n    }\n\n    void displayManager()\n    {\n        displayEmployee();\n\n        System.out.println(\"\\n----- MANAGER DETAILS -----\");\n\n        System.out.println(\"Salary: \" + salary);\n    }\n}\n\nclass SalesManager extends Manager\n{\n    double commission;\n\n    void getSalesManager()\n    {\n        getManager();\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Commission:\");\n        commission = sc.nextDouble();\n    }\n\n    void displaySalesManager()\n    {\n        displayManager();\n\n        System.out.println(\n        \"\\n----- SALES MANAGER DETAILS -----\");\n\n        System.out.println(\n        \"Commission: \" + commission);\n    }\n}\n\npublic class EmployeeHierarchy\n{\n    public static void main(String args[])\n    {\n        SalesManager s = new SalesManager();\n\n        s.getSalesManager();\n\n        s.displaySalesManager();\n    }\n}","q2":"/*\nWrite a program to implement patient information in a file and perform the file\noperations on it.\n*/\n\n//Create \n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass CreatePatientFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File file = new File(\"patient.txt\");\n\n            if(file.createNewFile())\n            {\n                System.out.println(\"File Created\");\n            }\n\n            Scanner sc = new Scanner(System.in);\n\n            System.out.println(\"Enter Patient ID:\");\n            int id = sc.nextInt();\n            sc.nextLine();\n\n            // Check Duplicate ID\n            boolean exists = false;\n\n            Scanner reader = new Scanner(file);\n\n            while(reader.hasNextLine())\n            {\n                String line = reader.nextLine();\n\n                if(line.startsWith(\"Patient ID:\"))\n                {\n                    int pid = Integer.parseInt(\n                              line.substring(11).trim());\n\n                    if(pid == id)\n                    {\n                        exists = true;\n                        break;\n                    }\n                }\n            }\n\n            reader.close();\n\n            if(exists)\n            {\n                System.out.println(\n                \"Patient ID Already Exists\");\n            }\n            else\n            {\n                FileWriter writer =\n                new FileWriter(file, true);\n\n                System.out.println(\n                \"Enter Patient Name:\");\n\n                String name = sc.nextLine();\n\n                System.out.println(\"Enter Disease:\");\n\n                String disease = sc.nextLine();\n\n                writer.write(\n                \"\\nPatient ID: \" + id + \"\\n\");\n\n                writer.write(\n                \"Patient Name: \" + name + \"\\n\");\n\n                writer.write(\n                \"Disease: \" + disease + \"\\n\");\n\n                writer.close();\n\n                System.out.println(\n                \"Patient Record Added\");\n            }\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n//Read\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass ReadPatientFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File file = new File(\"patient.txt\");\n\n            Scanner reader =\n            new Scanner(file);\n\n            System.out.println(\n            \"\\n----- PATIENT RECORDS -----\");\n\n            while(reader.hasNextLine())\n            {\n                System.out.println(\n                reader.nextLine());\n            }\n\n            reader.close();\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n//write\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass UpdatePatientFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File inputFile =\n            new File(\"patient.txt\");\n\n            File tempFile =\n            new File(\"temp.txt\");\n\n            BufferedReader br =\n            new BufferedReader(\n            new FileReader(inputFile));\n\n            BufferedWriter bw =\n            new BufferedWriter(\n            new FileWriter(tempFile));\n\n            Scanner sc =\n            new Scanner(System.in);\n\n            System.out.println(\n            \"Enter Patient ID to Update:\");\n\n            int updateId = sc.nextInt();\n            sc.nextLine();\n\n            String line;\n\n            boolean found = false;\n\n            while((line = br.readLine()) != null)\n            {\n                if(line.startsWith(\"Patient ID:\"))\n                {\n                    int id =\n                    Integer.parseInt(\n                    line.substring(11).trim());\n\n                    if(id == updateId)\n                    {\n                        found = true;\n\n                        // Skip old data\n                        br.readLine();\n                        br.readLine();\n\n                        System.out.println(\n                        \"Enter New Patient Name:\");\n\n                        String name =\n                        sc.nextLine();\n\n                        System.out.println(\n                        \"Enter New Disease:\");\n\n                        String disease =\n                        sc.nextLine();\n\n                        bw.write(\n                        \"Patient ID: \" + id);\n\n                        bw.newLine();\n\n                        bw.write(\n                        \"Patient Name: \" + name);\n\n                        bw.newLine();\n\n                        bw.write(\n                        \"Disease: \" + disease);\n\n                        bw.newLine();\n                    }\n\n                    else\n                    {\n                        bw.write(line);\n                        bw.newLine();\n\n                        bw.write(br.readLine());\n                        bw.newLine();\n\n                        bw.write(br.readLine());\n                        bw.newLine();\n                    }\n                }\n            }\n\n            br.close();\n            bw.close();\n\n            inputFile.delete();\n\n            tempFile.renameTo(inputFile);\n\n            if(found)\n                System.out.println(\n                \"Record Updated\");\n\n            else\n                System.out.println(\n                \"Patient Not Found\");\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}\n\n//Delete\n\nimport java.io.*;\nimport java.util.Scanner;\n\nclass DeletePatientFile\n{\n    public static void main(String args[])\n    {\n        try\n        {\n            File inputFile =\n            new File(\"patient.txt\");\n\n            File tempFile =\n            new File(\"temp.txt\");\n\n            BufferedReader br =\n            new BufferedReader(\n            new FileReader(inputFile));\n\n            BufferedWriter bw =\n            new BufferedWriter(\n            new FileWriter(tempFile));\n\n            Scanner sc =\n            new Scanner(System.in);\n\n            System.out.println(\n            \"Enter Patient ID to Delete:\");\n\n            int deleteId = sc.nextInt();\n\n            String line;\n\n            while((line = br.readLine()) != null)\n            {\n                if(line.startsWith(\"Patient ID:\"))\n                {\n                    int id =\n                    Integer.parseInt(\n                    line.substring(11).trim());\n\n                    String name =\n                    br.readLine();\n\n                    String disease =\n                    br.readLine();\n\n                    if(id != deleteId)\n                    {\n                        bw.write(line);\n                        bw.newLine();\n\n                        bw.write(name);\n                        bw.newLine();\n\n                        bw.write(disease);\n                        bw.newLine();\n                    }\n                }\n            }\n\n            br.close();\n            bw.close();\n\n            inputFile.delete();\n\n            tempFile.renameTo(inputFile);\n\n            System.out.println(\n            \"Record Deleted\");\n        }\n\n        catch(Exception e)\n        {\n            System.out.println(e);\n        }\n    }\n}"},{"id":17,"q1":"/*\nImplement a Java Program for creating a digital clock using AWT, Swing & Date\nclass.\n*/\n\nimport java.awt.*;\nimport java.awt.event.*;\nimport java.text.SimpleDateFormat;\nimport java.util.Date;\nimport javax.swing.*;\n\npublic class DigitalClock extends JFrame\nimplements ActionListener\n{\n    private JLabel clockLabel;\n\n    private Timer timer;\n\n    public DigitalClock()\n    {\n        setLayout(new FlowLayout());\n\n        clockLabel =\n        new JLabel(\"\", SwingConstants.CENTER);\n\n        clockLabel.setFont(\n        new Font(\"Arial\", Font.BOLD, 30));\n\n        add(clockLabel);\n\n        timer = new Timer(1000, this);\n\n        timer.start();\n\n        setTitle(\"Digital Clock\");\n\n        setDefaultCloseOperation(\n        EXIT_ON_CLOSE);\n\n        setSize(300, 150);\n\n        setLocationRelativeTo(null);\n\n        setVisible(true);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        Date date = new Date();\n\n        SimpleDateFormat format =\n        new SimpleDateFormat(\"hh:mm:ss a\");\n\n        String clockText =\n        format.format(date);\n\n        clockLabel.setText(clockText);\n    }\n\n    public static void main(String[] args)\n    {\n        new DigitalClock();\n    }\n}","q2":"/*Write a program to design an admission enquiry for MCA student form using\nSwing.*/\n\n\nimport javax.swing.*;\nimport java.awt.*;\nimport java.awt.event.*;\n\nclass MCAAdmissionForm extends JFrame implements ActionListener\n{\n    JLabel l1, l2, l3, l4, l5, l6;\n    JTextField t1, t2, t3;\n    JRadioButton r1, r2;\n    JComboBox c1;\n    JButton b1;\n\n    MCAAdmissionForm()\n    {\n        setTitle(\"MCA Admission Enquiry Form\");\n\n        l1 = new JLabel(\"Student Name:\");\n        l2 = new JLabel(\"Mobile Number:\");\n        l3 = new JLabel(\"Email ID:\");\n        l4 = new JLabel(\"Gender:\");\n        l5 = new JLabel(\"City:\");\n        l6 = new JLabel(\"Course:\");\n\n        t1 = new JTextField();\n        t2 = new JTextField();\n        t3 = new JTextField();\n\n        r1 = new JRadioButton(\"Male\");\n        r2 = new JRadioButton(\"Female\");\n\n        ButtonGroup bg = new ButtonGroup();\n        bg.add(r1);\n        bg.add(r2);\n\n        String course[] = {\"MCA\", \"MBA\", \"MSc IT\"};\n        c1 = new JComboBox(course);\n\n        b1 = new JButton(\"Submit\");\n\n        setLayout(null);\n\n        l1.setBounds(50, 50, 120, 30);\n        t1.setBounds(180, 50, 150, 30);\n\n        l2.setBounds(50, 100, 120, 30);\n        t2.setBounds(180, 100, 150, 30);\n\n        l3.setBounds(50, 150, 120, 30);\n        t3.setBounds(180, 150, 150, 30);\n\n        l4.setBounds(50, 200, 120, 30);\n        r1.setBounds(180, 200, 80, 30);\n        r2.setBounds(260, 200, 80, 30);\n\n        l5.setBounds(50, 250, 120, 30);\n\n        String city[] = {\"Mumbai\", \"Pune\", \"Nashik\"};\n        JComboBox cityBox = new JComboBox(city);\n        cityBox.setBounds(180, 250, 150, 30);\n\n        l6.setBounds(50, 300, 120, 30);\n        c1.setBounds(180, 300, 150, 30);\n\n        b1.setBounds(150, 370, 100, 30);\n\n        add(l1);\n        add(t1);\n\n        add(l2);\n        add(t2);\n\n        add(l3);\n        add(t3);\n\n        add(l4);\n        add(r1);\n        add(r2);\n\n        add(l5);\n        add(cityBox);\n\n        add(l6);\n        add(c1);\n\n        add(b1);\n\n        b1.addActionListener(this);\n\n        setSize(450, 500);\n        setVisible(true);\n        setDefaultCloseOperation(JFrame.EXIT_ON_CLOSE);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        JOptionPane.showMessageDialog(this,\n                \"Admission Enquiry Submitted Successfully\");\n    }\n\n    public static void main(String args[])\n    {\n        new MCAAdmissionForm();\n    }\n}"},{"id":18,"q1":"/* Develop a Java-based library management application that demonstrates OOP\nprinciples and uses exception handling to handle cases like issuing books, returning\nbooks, etc.\n*/\n\nimport java.util.Scanner;\n\nclass Book\n{\n    int id;\n    String name, author;\n    boolean available = true;\n\n    void addBook()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Book ID:\");\n        id = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Book Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Author Name:\");\n        author = sc.nextLine();\n    }\n\n    void display()\n    {\n        System.out.println(\"\\nBook ID: \" + id);\n        System.out.println(\"Book Name: \" + name);\n        System.out.println(\"Author Name: \" + author);\n\n        if(available)\n            System.out.println(\"Status: Available\");\n        else\n            System.out.println(\"Status: Issued\");\n    }\n}\n\nclass Library extends Book\n{\n    // Polymorphism (Method Overriding)\n    void display()\n    {\n        super.display();\n\n        if(available)\n            System.out.println(\"Book can be issued.\");\n        else\n            System.out.println(\"Book is not available.\");\n    }\n}\n\npublic class LibraryManagement\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Library b[] = new Library[10];\n\n        int count = 0, choice;\n\n        do\n        {\n            System.out.println(\"\\n===== LIBRARY MENU =====\");\n\n            System.out.println(\"1. Add Book\");\n            System.out.println(\"2. Display Books\");\n            System.out.println(\"3. Issue Book\");\n            System.out.println(\"4. Return Book\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n\n                    b[count] = new Library();\n\n                    b[count].addBook();\n\n                    count++;\n\n                    System.out.println(\"Book Added.\");\n                    break;\n\n                case 2:\n\n                    if(count == 0)\n                    {\n                        System.out.println(\"No Books Found.\");\n                    }\n                    else\n                    {\n                        for(int i=0; i<count; i++)\n                        {\n                            b[i].display();\n                        }\n                    }\n\n                    break;\n\n                case 3:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Issue:\");\n\n                        int issueId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == issueId)\n                            {\n                                found = true;\n\n                                if(b[i].available)\n                                {\n                                    b[i].available = false;\n\n                                    System.out.println(\n                                            \"Book Issued Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \" Exception : Book Already Issued.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 4:\n\n                    try\n                    {\n                        System.out.println(\n                                \"Enter Book ID to Return:\");\n\n                        int returnId = sc.nextInt();\n\n                        boolean found = false;\n\n                        for(int i=0; i<count; i++)\n                        {\n                            if(b[i].id == returnId)\n                            {\n                                found = true;\n\n                                if(!b[i].available)\n                                {\n                                    b[i].available = true;\n\n                                    System.out.println(\n                                            \"Book Returned Successfully.\");\n                                }\n                                else\n                                {\n                                    throw new Exception(\n                                            \"Exception : Book Already Returned.\");\n                                }\n                            }\n                        }\n\n                        if(!found)\n                        {\n                            throw new Exception(\n                                    \"Invalid Book ID.\");\n                        }\n                    }\n\n                    catch(Exception e)\n                    {\n                        System.out.println(e.getMessage());\n                    }\n\n                    break;\n\n                case 5:\n\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}","q2":"/*Write a program to demonstrate how the process tasks asynchronously in a Spring\nBoot application.*/\n\n/* 1.go to start.spring.import \n2.download file \n3.open the file in intellij and run the application\n4.go to src/main/java/com/example/demo/DemoApplication.java\n5.create class AsyncService,AsyncController,AsyncDemoApplication */\n\n/* ADD code in AsyncDemoApplication.java */\npackage com.example.firstdemo;\n\nimport org.springframework.boot.SpringApplication;\nimport org.springframework.boot.autoconfigure.SpringBootApplication;\nimport org.springframework.scheduling.annotation.EnableAsync;\n\n@SpringBootApplication\n@EnableAsync\npublic class AsyncDemoApplication {\n    public static void main (String[] args) {\n        SpringApplication.run(AsyncDemoApplication.class, args);\n    }\n\n}\n\n\n/* Add code in AsyncService.java */\npackage com.example.firstdemo;\n\nimport org.springframework.scheduling.annotation.Async;\nimport org.springframework.stereotype.Service;\n\n@Service\npublic class AsyncService {\n\n    @Async\n    public void processTask() {\n        try {\n            System.out.println(\"Task started on thread: \" +\n                    Thread.currentThread().getName());\n\n            Thread.sleep(5000); // simulate long process (5 seconds)\n\n            System.out.println(\"Task completed on thread:\" +\n                    Thread.currentThread().getName());\n\n        } catch (InterruptedException e) {\n            e.printStackTrace();\n        }\n    }\n}\n\n/* Add code in AsyncController.java */\npackage com.example.firstdemo;\n\nimport org.springframework.beans.factory.annotation.Autowired;\nimport org.springframework.web.bind.annotation.GetMapping;\nimport org.springframework.web.bind.annotation.RestController;\n\n@RestController\npublic class AsyncController {\n\n    @Autowired\n    private AsyncService asyncService;\n\n    @GetMapping(\"/run\")\n    public String runTask() {\n        asyncService.processTask();\n        return \"Task triggered successfully\";\n    }\n}"},{"id":19,"q1":"/*Write a program to accept roll no. Marks from users. Throw user defined exception\nMarks out of Bound if marks are 100.*/\n\npackage ExceptionHandling;\n\nimport java.util.Scanner;\n\n// Custom Exception\nclass MarksOutOfBound extends Exception {\n    MarksOutOfBound(String msg) {\n        super(msg);\n    }\n}\n\npublic class Excep {\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n\n        int rollNo, marks;\n\n        System.out.print(\"Enter Roll No: \");\n        rollNo = sc.nextInt();\n\n        System.out.print(\"Enter Marks: \");\n        marks = sc.nextInt();\n\n        try {\n            if (marks > 100) {\n                throw new MarksOutOfBound(\"Marks should not be more than 100\");\n            }\n\n            System.out.println(\"Roll No: \" + rollNo);\n            System.out.println(\"Marks: \" + marks);\n\n        } catch (MarksOutOfBound e) {\n            System.out.println(\"Exception: \" + e.getMessage());\n        }\n\n        sc.close();\n    }\n}\n\n","q2":"/*\nCreate a Java application that connects to a MySQL database to manage employee\ninformation. Implement functionalities like adding, updating, deleting, and viewing\nemployee records using JDBC. Use prepared statements to prevent SQL injection\nand handle exceptions gracefully.\n\nTable :\n\nCREATE TABLE employee(\nid int primary key auto_increment,\nname varchar(100),\nsalary double,\ndepartment varchar(100));\n*/\n\n\n\npackage JAVAJDBC;\nimport java.sql.*;\nimport java.util.Scanner;\n\npublic class EmployeeApp {\n\n    static final String URL = \"jdbc:mysql://localhost:3306/company\";\n    static final String USER = \"root\";\n    static final String PASSWORD = \"@zekky@999\";\n\n    public static void main(String[] args) {\n\n        Scanner sc = new Scanner(System.in);\n\n        try {\n            Connection conn = DriverManager.getConnection(URL, USER, PASSWORD);\n\n            while (true) {\n                System.out.println(\"\\n1. Add Employee\");\n                System.out.println(\"2. View Employees\");\n                System.out.println(\"3. Update Employee\");\n                System.out.println(\"4. Delete Employee\");\n                System.out.println(\"5. Exit\");\n\n                System.out.print(\"Enter choice: \");\n                int choice = sc.nextInt();\n\n                switch (choice) {\n\n                    case 1:\n                        addEmployee(conn, sc);\n                        break;\n\n                    case 2:\n                        viewEmployees(conn);\n                        break;\n\n                    case 3:\n                        updateEmployee(conn, sc);\n                        break;\n\n                    case 4:\n                        deleteEmployee(conn, sc);\n                        break;\n\n                    case 5:\n                        conn.close();\n                        System.out.println(\"Exited Successfully!\");\n                        return;\n\n                    default:\n                        System.out.println(\"Invalid Choice!\");\n                }\n            }\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // ADD\n    public static void addEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"INSERT INTO employee(name, salary, department) VALUES (?, ?, ?)\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Name: \");\n            sc.nextLine();\n            String name = sc.nextLine();\n\n            System.out.print(\"Enter Salary: \");\n            double salary = sc.nextDouble();\n\n            System.out.print(\"Enter Department: \");\n            sc.nextLine();\n            String dept = sc.nextLine();\n\n            ps.setString(1, name);\n            ps.setDouble(2, salary);\n            ps.setString(3, dept);\n\n            ps.executeUpdate();\n            System.out.println(\"Employee Added!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // VIEW\n    public static void viewEmployees(Connection conn) {\n        try {\n            String sql = \"SELECT * FROM employee\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            ResultSet rs = ps.executeQuery();\n\n            System.out.println(\"\\n--- Employee List ---\");\n            while (rs.next()) {\n                System.out.println(\n                        rs.getInt(\"id\") + \" | \" +\n                                rs.getString(\"name\") + \" | \" +\n                                rs.getDouble(\"salary\") + \" | \" +\n                                rs.getString(\"department\"));\n            }\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // UPDATE\n    public static void updateEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"UPDATE employee SET salary=? WHERE id=?\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n\n            System.out.print(\"Enter New Salary: \");\n            double salary = sc.nextDouble();\n\n            ps.setDouble(1, salary);\n            ps.setInt(2, id);\n\n            int rows = ps.executeUpdate();\n\n            if (rows > 0)\n                System.out.println(\"Employee Updated!\");\n            else\n                System.out.println(\"Employee Not Found!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n\n    // DELETE\n    public static void deleteEmployee(Connection conn, Scanner sc) {\n        try {\n            String sql = \"DELETE FROM employee WHERE id=?\";\n            PreparedStatement ps = conn.prepareStatement(sql);\n\n            System.out.print(\"Enter Employee ID: \");\n            int id = sc.nextInt();\n\n            ps.setInt(1, id);\n\n            int rows = ps.executeUpdate();\n\n            if (rows > 0)\n                System.out.println(\"Employee Deleted!\");\n            else\n                System.out.println(\"Employee Not Found!\");\n\n        } catch (Exception e) {\n            System.out.println(\"Error: \" + e.getMessage());\n        }\n    }\n}\n\n"},{"id":20,"q1":"/* Implement a Java program to manage bank accounts using object-oriented\nprogramming (OOP) concepts like classes, inheritance, encapsulation, and\npolymorphism. Include features like account creation, deposit, withdrawal, and\nbalance inquiry.\n*/\n\nimport java.util.Scanner;\n\nclass Account\n{\n    int accNo;\n    String name;\n    double balance;\n\n    void createAccount()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Account Number:\");\n        accNo = sc.nextInt();\n        sc.nextLine();\n\n        System.out.println(\"Enter Account Holder Name:\");\n        name = sc.nextLine();\n\n        System.out.println(\"Enter Initial Balance:\");\n        balance = sc.nextDouble();\n\n        System.out.println(\"Account Created Successfully.\");\n    }\n\n    void display()\n    {\n        System.out.println(\"\\nAccount Number: \" + accNo);\n        System.out.println(\"Account Holder Name: \" + name);\n        System.out.println(\"Balance: \" + balance);\n    }\n}\n\nclass Bank extends Account\n{\n    void deposit()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Amount to Deposit:\");\n        double amt = sc.nextDouble();\n\n        balance = balance + amt;\n\n        System.out.println(\"Amount Deposited Successfully.\");\n    }\n\n    void withdraw()\n    {\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"Enter Amount to Withdraw:\");\n        double amt = sc.nextDouble();\n\n        if(balance >= amt)\n        {\n            balance = balance - amt;\n\n            System.out.println(\"Amount Withdrawn Successfully.\");\n        }\n        else\n        {\n            System.out.println(\"Insufficient Balance.\");\n        }\n    }\n\n    // Polymorphism (Method Overriding)\n    void display()\n    {\n        super.display();\n\n        System.out.println(\"Thank You for Banking.\");\n    }\n}\n\npublic class BankManagementSystem\n{\n    public static void main(String args[])\n    {\n        Scanner sc = new Scanner(System.in);\n\n        Bank b = new Bank();\n\n        int choice;\n\n        do\n        {\n            System.out.println(\"\\n===== BANK MENU =====\");\n\n            System.out.println(\"1. Create Account\");\n            System.out.println(\"2. Deposit\");\n            System.out.println(\"3. Withdraw\");\n            System.out.println(\"4. Balance Inquiry\");\n            System.out.println(\"5. Exit\");\n\n            System.out.println(\"Enter Choice:\");\n            choice = sc.nextInt();\n\n            switch(choice)\n            {\n                case 1:\n                    b.createAccount();\n                    break;\n\n                case 2:\n                    b.deposit();\n                    break;\n\n                case 3:\n                    b.withdraw();\n                    break;\n\n                case 4:\n                    b.display();\n                    break;\n\n                case 5:\n                    System.out.println(\"Exiting...\");\n                    break;\n\n                default:\n                    System.out.println(\"Invalid Choice\");\n            }\n\n        } while(choice != 5);\n    }\n}","q2":"/*Write a program of servlet to demonstrate GET and POST Methods with suitable\nexample using simulation.*/\n\n\nimport java.util.Scanner;\n\npublic class RequestSimulator {\n\n    // Simulating GET method\n    public static void doGet(String name, String age) {\n        System.out.println(\"\\n--- GET Method Execution ---\");\n        System.out.println(\"URL: http://localhost:8080/student?name=\" + name +\n                \"&age=\" + age);\n\n        System.out.println(\"Data received using GET method:\");\n        System.out.println(\"Name: \" + name);\n        System.out.println(\"Age: \" + age);\n    }\n\n    // Simulating POST method\n    public static void doPost(String name, String age) {\n        System.out.println(\"\\n--- POST Method Execution ---\");\n        System.out.println(\"URL: http://localhost:8080/student\");\n        System.out.println(\"(Data is sent in request body, not visible in URL)\");\n\n        System.out.println(\"Data received using POST method:\");\n        System.out.println(\"Name: \" + name);\n        System.out.println(\"Age: \" + age);\n    }\n\n    public static void main(String[] args) {\n\n        Scanner sc = new Scanner(System.in);\n\n        System.out.println(\"=== Servlet GET/POST Simulation ===\");\n\n        // Taking input\n        System.out.print(\"Enter Name: \");\n        String name = sc.nextLine();\n\n        System.out.print(\"Enter Age: \");\n        String age = sc.nextLine();\n\n        // Choosing method\n        System.out.println(\"\\nChoose Method:\");\n        System.out.println(\"1. GET\");\n        System.out.println(\"2. POST\");\n        System.out.print(\"Enter choice: \");\n\n        int choice = sc.nextInt();\n\n        // Calling respective method\n        if (choice == 1) {\n            doGet(name, age);\n        } else if (choice == 2) {\n            doPost(name, age);\n        } else {\n            System.out.println(\"Invalid choice!\");\n        }\n\n        sc.close();\n    }\n}\n"}];
const EXTRAS_RAW = [{"id":"extra-0","fileName":"MCAAdmissionFormWithPassword.txt","content":"//Admission Form With Password\n\n\nimport javax.swing.*;\nimport java.awt.*;\nimport java.awt.event.*;\n\nclass MCAAdmissionForm extends JFrame\n        implements ActionListener\n{\n    JLabel l1, l2, l3, l4, l5, l6, l7;\n\n    JTextField t1, t2, t3;\n\n    JPasswordField p1;\n\n    JRadioButton r1, r2;\n\n    JComboBox c1;\n\n    JButton b1;\n\n    MCAAdmissionForm()\n    {\n        setTitle(\"MCA Admission Enquiry Form\");\n\n        l1 = new JLabel(\"Student Name:\");\n        l2 = new JLabel(\"Mobile Number:\");\n        l3 = new JLabel(\"Email ID:\");\n        l4 = new JLabel(\"Gender:\");\n        l5 = new JLabel(\"City:\");\n        l6 = new JLabel(\"Course:\");\n        l7 = new JLabel(\"Password:\");\n\n        t1 = new JTextField();\n        t2 = new JTextField();\n        t3 = new JTextField();\n\n        p1 = new JPasswordField();\n\n        r1 = new JRadioButton(\"Male\");\n        r2 = new JRadioButton(\"Female\");\n\n        ButtonGroup bg = new ButtonGroup();\n\n        bg.add(r1);\n        bg.add(r2);\n\n        String course[] =\n                {\"MCA\", \"MBA\", \"MSc IT\"};\n\n        c1 = new JComboBox(course);\n\n        b1 = new JButton(\"Submit\");\n\n        setLayout(null);\n\n        l1.setBounds(50, 50, 120, 30);\n        t1.setBounds(180, 50, 150, 30);\n\n        l2.setBounds(50, 100, 120, 30);\n        t2.setBounds(180, 100, 150, 30);\n\n        l3.setBounds(50, 150, 120, 30);\n        t3.setBounds(180, 150, 150, 30);\n\n        l7.setBounds(50, 200, 120, 30);\n        p1.setBounds(180, 200, 150, 30);\n\n        l4.setBounds(50, 250, 120, 30);\n        r1.setBounds(180, 250, 80, 30);\n        r2.setBounds(260, 250, 80, 30);\n\n        l5.setBounds(50, 300, 120, 30);\n\n        String city[] =\n                {\"Mumbai\", \"Pune\", \"Nashik\"};\n\n        JComboBox cityBox =\n                new JComboBox(city);\n\n        cityBox.setBounds(180, 300, 150, 30);\n\n        l6.setBounds(50, 350, 120, 30);\n        c1.setBounds(180, 350, 150, 30);\n\n        b1.setBounds(150, 420, 100, 30);\n\n        add(l1);\n        add(t1);\n\n        add(l2);\n        add(t2);\n\n        add(l3);\n        add(t3);\n\n        add(l7);\n        add(p1);\n\n        add(l4);\n        add(r1);\n        add(r2);\n\n        add(l5);\n        add(cityBox);\n\n        add(l6);\n        add(c1);\n\n        add(b1);\n\n        b1.addActionListener(this);\n\n        setSize(450, 550);\n\n        setVisible(true);\n\n        setDefaultCloseOperation(\n                JFrame.EXIT_ON_CLOSE);\n    }\n\n    public void actionPerformed(ActionEvent e)\n    {\n        JOptionPane.showMessageDialog(this,\n                \"Admission Enquiry Submitted Successfully\");\n    }\n\n    public static void main(String args[])\n    {\n        new MCAAdmissionForm();\n    }\n}"},{"id":"extra-1","fileName":"SpringBoot.txt","content":"/*\nsteps to setup a spring boot project with intellij\n\ngo to start.spring.io or spring initializer in browser \n\nProject : Maven \nLanguage : Java\nSpring Boot Version : latest \nProject Metadata :\nGroup : com.example \nArtifact : demo\nName : demo\nDescription : demo project for spring boot\nPackage name : com.example.demo\nPackaging : Jar\nJava : 17 (latest version installed on your machine)\nDependencies : Spring Web \\\nclick on generate and download the project\nunzip the downloaded project and open it in intellij\nclick on project structure and set the project sdk to java 17 or the version you have installed\n\nnow \nclick on  src -> main -> java -> com.example.demo -> DemoApplication.java\nclick on DemoApplication.java and run it \nclick on it only and create other java classes in the same package com.example.demo\ncheck on localhost:8080 in your browser to see the default spring boot page\nif not shown , change the port no , click on resources -> application.properties -> \nspring.application.name=demo\nserver.port=8081 \nnow it will run \n*/"},{"id":"extra-2","fileName":"MysqlInstallation.txt","content":"/*\nProcedure To Download Mysql server and connectorj \n\nMysql server download link: https://dev.mysql.com/downloads/mysql/\n\nSteps for Mysql server:\n\nsearch Mysql install\nselect the first link and click on it\nselect windows(x86, 32 bit (with most downloads)) msi installer and click on download\nno thanks and continue download\nclick on the downloaded file \nfull->next->next->execute->next->next->next->password(root)->next->next->execute->finish-\n\n\n\n\n\n\n\n\n\n\n\nConnectorj download link: https://dev.mysql.com/downloads/connector/j/\nsteps for Mysql connectorj:\n \nsearch \"Download Mysql Connnectorj \"\nselect the first link and click on it\nselect platform independent and click on download\nselect platform independent (Architecture Independent)Zip Archive, and click on download\nExtract the downloaded file\nopen intellij and create an new project \nclick on 3 lines on top corner \nselect project structure\nselect libraries and click on + icon \nselect java and then go were you downloaded and extracted the connectorj file\nselect .jar file and click on ok\nthen click on apply and ok\nit should appear on External Libraries\n\n*/"},{"id":"extra-3","fileName":"small-file-handling.txt","content":"//filehandling small codes\n\n\npackage SmallFileHandling;\n\nimport java.io.FileWriter;\nimport java.io.IOException;\nimport java.util.Scanner;\n\n//Write\n\npublic class WriteEmployee {\n    public static void main(String[] var0) {\n        Scanner var1 = new Scanner(System.in);\n\n        try {\n            FileWriter var2 = new FileWriter(\"employee.txt\", true);\n            System.out.print(\"Enter Employee ID: \");\n            int var3 = var1.nextInt();\n            var1.nextLine();\n            System.out.print(\"Enter Employee Name: \");\n            String var4 = var1.nextLine();\n            System.out.print(\"Enter Employee Salary: \");\n            double var5 = var1.nextDouble();\n            var2.write(\"ID: \" + var3 + \"\\n\");\n            var2.write(\"Name: \" + var4 + \"\\n\");\n            var2.write(\"Salary: \" + var5 + \"\\n\");\n            var2.write(\"----------------------\\n\");\n            var2.close();\n            System.out.println(\"Employee data written successfully.\");\n        } catch (IOException var7) {\n            System.out.println(\"Error: \" + var7);\n        }\n\n        var1.close();\n    }\n}\n\n\n//Read\n\npackage SmallFileHandling;\n\nimport java.io.File;\nimport java.io.FileNotFoundException;\nimport java.util.Scanner;\n\npublic class ReadEmployee {\n    public static void main(String[] args) {\n\n        try {\n            File file = new File(\"employee.txt\");\n            Scanner sc = new Scanner(file);\n\n            System.out.println(\"Employee Details:\\n\");\n\n            while (sc.hasNextLine()) {\n                System.out.println(sc.nextLine());\n            }\n\n            sc.close();\n\n        } catch (FileNotFoundException e) {\n            System.out.println(\"File not found.\");\n        }\n    }\n}\n\n\n//delete \n\npackage SmallFileHandling;\n\n\nimport java.io.*;\n\npublic class DeleteEmployee\n{\n    public static void main(String[] args)\n    {\n        File myFile = new File(\"employee.txt\");\n\n        if(myFile.delete())\n        {\n            System.out.println(\"Employee Record Deleted : \" + myFile.getName());\n        }\n\n        else\n        {\n            System.out.println(\"Employee Record not deleted !\");\n        }\n    }\n}"}];
